                </li>
              </ul>
              <p v-else>{{ projectDeliverablesPlaceholder }}</p>
              <div v-if="referenceAttachments.length" class="review-attachment-list">
                <strong>{{ referenceAttachments.length }} reference files</strong>
                <span v-for="attachment in referenceAttachments.slice(0, 3)" :key="attachment.id">
                  {{ attachment.original_name }}
                </span>
              </div>
            </section>

            <section class="review-card">
              <button type="button" aria-label="Edit budget" @click="goProjectStep(3)">
                <PenLine :size="15" />
              </button>
