            <div>
              <dt>Budget</dt>
              <dd>{{ projectBudgetRangeLabel }}</dd>
            </div>
            <div>
              <dt>Timeline</dt>
              <dd>{{ projectTimelineLabel }}</dd>
            </div>
            <div>
              <dt>Experience</dt>
              <dd>Intermediate - Expert</dd>
            </div>
            <div>
              <dt>Deliverables</dt>
              <dd>{{ projectDeliverableCountLabel }}</dd>
            </div>
          </dl>
