    <section
      v-if="projectPreviewVisible"
      class="project-preview-backdrop"
      role="dialog"
      aria-modal="true"
      aria-labelledby="project-preview-title"
      @click.self="closeProjectPreview"
      @keydown.esc="closeProjectPreview"
    >
      <article ref="projectPreviewDialog" class="project-preview-dialog" tabindex="-1">
        <header class="project-preview-header">
          <div>
            <span class="project-preview-kicker">
              <Eye :size="15" />
              Marketplace project preview
            </span>
            <h2 id="project-preview-title">{{ projectTitleLabel }}</h2>
            <p>{{ projectDescriptionLabel }}</p>
          </div>
          <button class="project-preview-close" type="button" aria-label="Close project preview" @click="closeProjectPreview">
            <X :size="18" />
          </button>
        </header>

        <div class="project-preview-body">
          <section class="project-preview-hero">
            <div class="project-preview-avatar">{{ projectInitial }}</div>
            <div>
              <span>{{ projectTypeLabel }}</span>
              <strong>{{ projectBudgetRangeLabel }}</strong>
              <small>{{ projectTimelineLabel }}</small>
            </div>
            <div class="project-preview-quality">
              <b>{{ projectQualityScoreLabel }}</b>
              <span>Quality score</span>
            </div>
          </section>

          <div v-if="projectPreviewTags.length" class="project-preview-tags">
            <span v-for="tag in projectPreviewTags" :key="tag">{{ tag }}</span>
          </div>

          <div class="project-preview-grid">
            <section class="project-preview-section wide">
              <h3>
                <FileCheck2 :size="17" />
                Project overview
              </h3>
              <p>{{ projectPreviewOverview }}</p>
            </section>

            <section class="project-preview-section">
              <h3>
                <ListTodo :size="17" />
                Deliverables
              </h3>
              <ul v-if="visibleDeliverables.length">
                <li v-for="deliverable in visibleDeliverables" :key="deliverable">
                  <CheckCircle2 :size="14" />
                  {{ deliverable }}
                </li>
              </ul>
              <p v-else>{{ projectDeliverablesPlaceholder }}</p>
            </section>

            <section class="project-preview-section">
              <h3>
                <ShieldCheck :size="17" />
                Requirements
              </h3>
              <ul v-if="projectPreviewRequirements.length">
                <li v-for="requirement in projectPreviewRequirements" :key="requirement">
                  <CheckCircle2 :size="14" />
                  {{ requirement }}
                </li>
              </ul>
              <p v-else>No additional constraints.</p>
            </section>

            <section class="project-preview-section">
              <h3>
                <CircleDollarSign :size="17" />
                Budget and escrow
              </h3>
              <dl>
                <div>
                  <dt>Budget</dt>
                  <dd>{{ projectBudgetRangeLabel }}</dd>
                </div>
                <div>
                  <dt>Platform fee</dt>
                  <dd>{{ formatMRG(projectPlatformFeeLow) }} - {{ formatMRG(projectPlatformFeeHigh) }}</dd>
                </div>
                <div>
                  <dt>Escrow fee</dt>
                  <dd>{{ formatMRG(projectEscrowFeeLow) }} - {{ formatMRG(projectEscrowFeeHigh) }}</dd>
                </div>
                <div class="strong-row">
                  <dt>Estimated total</dt>
                  <dd>{{ projectEstimatedRangeLabel }}</dd>
                </div>
              </dl>
            </section>

            <section class="project-preview-section">
              <h3>
                <Bot :size="17" />
                Delivery lane
              </h3>
              <dl>
                <div>
                  <dt>Funding</dt>
                  <dd>{{ projectSetupForm.fundingMethod }}</dd>
                </div>
                <div>
                  <dt>Visibility</dt>
                  <dd>{{ projectSetupForm.visibility }}</dd>
                </div>
                <div>
                  <dt>AI agents</dt>
                  <dd>{{ projectSetupForm.allowAgents ? 'Allowed' : 'Disabled' }}</dd>
                </div>
                <div>
                  <dt>References</dt>
                  <dd>{{ referenceAttachments.length ? `${referenceAttachments.length} file${referenceAttachments.length === 1 ? '' : 's'}` : 'None' }}</dd>
                </div>
              </dl>
            </section>

            <section v-if="referenceAttachments.length" class="project-preview-section wide">
              <h3>
                <UploadCloud :size="17" />
                Reference files
              </h3>
              <div class="project-preview-files">
                <span v-for="attachment in referenceAttachments" :key="attachment.id">
                  <FileCheck2 :size="14" />
                  {{ attachment.original_name }}
                </span>
              </div>
            </section>
          </div>
        </div>

        <footer class="project-preview-actions">
          <button class="secondary-button compact" type="button" @click="editProjectPreviewStep(2)">
            <PenLine :size="15" />
            Edit scope
          </button>
          <button class="primary-button compact" type="button" @click="publishProjectFromPreview">
            Publish project
            <SendHorizontal :size="15" />
          </button>
        </footer>
      </article>
    </section>

    <footer class="project-flow-footer">
      <div class="footer-progress">
        <span>Step {{ footerStepNumber }} of 4</span>
        <i><b :style="{ width: `${footerProgress}%` }" /></i>
      </div>
      <nav aria-label="Project flow progress">
        <span
          v-for="item in projectFooterSteps"
          :key="item.label"
          :class="{ active: item.active, done: item.done, invalid: item.invalid }"
        >
          <CheckCircle2 v-if="item.done" :size="15" />
          <small v-else>{{ item.number }}</small>
          {{ item.label }}
        </span>
      </nav>
      <p>
        <ShieldCheck :size="17" />
        {{ footerProtectionCopy }}
      </p>
    </footer>
  </div>

  <div
    v-else-if="user && !publicModeVisible"
