            <span :class="['public-card-icon', metric.tone]">
              <component :is="metric.icon" :size="18" />
            </span>
            <div>
              <strong>{{ metric.value }}</strong>
              <small>{{ metric.label }}</small>
            </div>
          </article>
        </div>
      </section>

      <section class="dashboard-role-map" aria-label="Dashboard role coverage">
        <article
          v-for="role in dashboardRoleCoverageRows"
