                    </button>
                    <button type="button" @click="openPublicPage('ledger')">
                      <Link2 :size="13" />
                      Public Ledger
                    </button>
                  </div>
                </article>

                <div class="watching-line">
                  <CreditCard :size="14" />
                  {{ dashboardPaymentRows.length }} payment events loaded
                </div>
              </section>
            </template>
          </template>

          <template v-else-if="dashboardSection === 'admin'">
            <div class="dash-breadcrumb">
              <Home :size="14" />
