                    <Link2 :size="12" />
                  </a>
                </article>
              </section>

              <section class="dash-card admin-governance-card" aria-label="Admin governance runbook">
                <div class="card-title-row">
                  <div>
                    <h2>Governance Runbook</h2>
                    <p>Treasury, dispute, payout, moderation, and ledger checkpoints for operators before release.</p>
                  </div>
                  <span>{{ adminGovernanceActiveCount }} active</span>
                </div>
                <div class="admin-governance-grid">
                  <article v-for="row in adminGovernanceRows" :key="row.key">
                    <div class="admin-governance-top">
                      <span :class="['ledger-trust-icon', row.tone]">
                        <component :is="row.icon" :size="15" />
                      </span>
                      <div>
                        <small>{{ row.sourceLabel }}</small>
                        <strong>{{ row.title }}</strong>
                      </div>
                      <b :class="row.statusTone">{{ row.status }}</b>
                    </div>
                    <p>{{ row.body }}</p>
                    <dl class="admin-governance-meta">
                      <div>
                        <dt>Signal</dt>
                        <dd>{{ row.signal }}</dd>
                      </div>
                      <div>
                        <dt>Proof</dt>
                        <dd>{{ row.proof }}</dd>
                      </div>
                      <div>
                        <dt>Queue</dt>
                        <dd>{{ row.queue }}</dd>
                      </div>
                    </dl>
                    <div class="admin-governance-actions">
                      <button type="button" @click="dashboardSearch = row.searchTerm">
                        Show signals
                        <ArrowRight :size="12" />
                      </button>
                      <button type="button" @click="copyAdminGovernanceCheckpoint(row)">
                        Copy
                        <Link2 :size="12" />
                      </button>
                    </div>
                  </article>
                </div>
              </section>

              <section class="dash-card admin-dispute-card">
                <div class="card-title-row">
                  <div>
                    <h2>Dispute Center</h2>
                    <p>Payout approvals, customer disputes, moderation, and fraud review lanes.</p>
                  </div>
                  <span>{{ Number(adminConsole.disputes?.stats?.total_count) || 0 }} signals</span>
                </div>
                <div v-if="adminDisputeLanes.length" class="admin-dispute-grid">
                  <article v-for="lane in adminDisputeLanes" :key="lane.id" class="admin-dispute-lane">
                    <div class="admin-dispute-lane-head">
                      <span :class="['notification-dot', lane.tone]" />
                      <div>
                        <strong>{{ lane.title }}</strong>
                        <small>{{ lane.count }} total / {{ lane.critical }} critical / {{ lane.reward }}</small>
                      </div>
                    </div>
                    <p>{{ lane.body }}</p>
                    <div v-if="lane.items.length" class="admin-dispute-items">
                      <article v-for="item in lane.items" :key="item.id" class="admin-dispute-item">
                        <span :class="['ledger-event-type', item.tone]">{{ item.severity }}</span>
                        <div class="admin-dispute-item-copy">
                          <strong>{{ item.title }}</strong>
                          <small v-if="item.auditLabel">{{ item.auditLabel }}</small>
                          <small v-if="item.nextAction">{{ item.nextAction }}</small>
                          <small>{{ item.project }} / {{ item.status }}</small>
                        </div>
                        <div class="admin-dispute-item-actions">
                          <button
                            v-for="action in item.queueActions"
                            :key="action.key"
                            type="button"
                            :class="{ 'link-action': action.type === 'open_url' }"
                            :disabled="adminOpsQueueActionBusy(item, action)"
                            @click="handleAdminOpsQueueAction(item, action)"
                          >
                            <component :is="adminOpsQueueActionIcon(action)" :size="12" />
                            {{ adminOpsQueueActionRunning(item, action) ? 'Running' : action.label }}
                          </button>
                          <a v-if="item.url && !item.queueActions.length" :href="item.url" target="_blank" rel="noreferrer" aria-label="Open dispute evidence">
                            <Link2 :size="12" />
                          </a>
                          <button
                            v-if="item.canExecute"
                            type="button"
                            :disabled="releasingTaskID === item.id"
                            @click="executeAdminOpsAction(item)"
                          >
                            {{ releasingTaskID === item.id ? item.busyLabel : item.actionLabel }}
                          </button>
                        </div>
                      </article>
                    </div>
                    <small v-else>{{ dashboardSearch ? 'No matching signals' : 'No open signals' }}</small>
                  </article>
                </div>
                <article v-else class="dash-empty-state compact">
                  <strong>{{ adminConsoleLoading ? 'Loading dispute center...' : 'No dispute lanes' }}</strong>
                  <p>{{ adminConsoleLoading ? 'Syncing admin moderation lanes.' : 'Admin dispute and moderation lanes will appear here.' }}</p>
                </article>
              </section>

              <section class="dash-card admin-ops-card">
                <div class="card-title-row">
                  <div>
                    <h2>Ops Queue</h2>
                    <p>Review submissions, disputes, moderation, fraud, security, and payout audit signals.</p>
                  </div>
                  <span>{{ adminOpsRows.length }} rows</span>
                </div>
                <div v-if="adminOpsRows.length" class="admin-ops-list">
                  <article v-for="item in adminOpsRows" :key="item.id" class="admin-ops-row">
                    <span :class="['ledger-event-type', item.tone]">{{ item.severity }}</span>
                    <div>
                      <strong>{{ item.title }}</strong>
                      <p>{{ item.body }}</p>
                      <small v-if="item.nextAction">{{ item.nextAction }}</small>
                      <small v-if="item.auditLabel || item.amount">{{ item.auditLabel }}<template v-if="item.auditLabel && item.amount"> / </template>{{ item.amount }}</small>
                      <small>{{ item.project }} - {{ item.task || item.reference }} - {{ item.when }}</small>
                    </div>
                    <b>{{ item.status }}</b>
                    <div class="admin-ops-row-actions">
                      <button
                        v-for="action in item.queueActions"
                        :key="action.key"
                        type="button"
                        :class="{ 'link-action': action.type === 'open_url' }"
                        :disabled="adminOpsQueueActionBusy(item, action)"
                        @click="handleAdminOpsQueueAction(item, action)"
                      >
                        <component :is="adminOpsQueueActionIcon(action)" :size="12" />
                        {{ adminOpsQueueActionRunning(item, action) ? 'Running' : action.label }}
                      </button>
                      <a v-if="item.url && !item.queueActions.length" :href="item.url" target="_blank" rel="noreferrer">
                        <Link2 :size="12" />
                        Open
                      </a>
                      <button v-if="item.canExecute" type="button" :disabled="releasingTaskID === item.id" @click="executeAdminOpsAction(item)">
                        {{ releasingTaskID === item.id ? item.busyLabel : item.actionLabel }}
                      </button>
                      <div v-if="item.canDecideProposal" class="admin-ops-decision-actions">
                        <button
                          type="button"
                          :disabled="adminProposalDecisionID === item.proposalID"
                          @click="decideAdminOpsProposal(item, 'accepted')"
                        >
                          <CheckCircle2 :size="12" />
                          Accept
                        </button>
                        <button
                          class="decline"
                          type="button"
                          :disabled="adminProposalDecisionID === item.proposalID"
                          @click="decideAdminOpsProposal(item, 'declined')"
                        >
                          <X :size="12" />
                          Decline
                        </button>
                      </div>
                    </div>
                  </article>
                </div>
                <article v-else class="dash-empty-state compact">
                  <strong>{{ adminConsoleLoading ? 'Loading ops queue...' : 'No admin ops items' }}</strong>
                  <p>{{ adminConsoleLoading ? 'Fetching moderation and payout signals.' : 'Review submissions and moderation alerts will appear here.' }}</p>
                </article>
              </section>

              <section class="admin-console-grid">
                <article class="dash-card">
                  <div class="card-title-row">
                    <h2>Payout Audit</h2>
                    <span>{{ adminPayoutRows.length }}</span>
                  </div>
                  <div v-if="adminPayoutRows.length" class="admin-payout-list">
                    <article v-for="row in adminPayoutRows" :key="row.key">
                      <div>
                        <strong>{{ row.amount }}</strong>
                        <small>{{ row.type }} В· {{ row.when }}</small>
                      </div>
                      <span>{{ row.account }}</span>
                      <b>{{ row.status }}</b>
                      <small v-if="row.auditLabel">{{ row.auditLabel }}</small>
                      <small>{{ row.task }} В· {{ row.reference }}</small>
                    </article>
                  </div>
                  <article v-else class="dash-empty-state compact">
                    <strong>No payout rows</strong>
                    <p>Released task payments and manual credits will be audited here.</p>
                  </article>
                </article>

                <article class="dash-card">
                  <div class="card-title-row">
                    <div>
                      <h2>User Governance</h2>
                      <p>Role, identity, spend, and worker-risk controls for admin moderation.</p>
                    </div>
                    <span>{{ adminUserRows.length }}</span>
                  </div>
                  <div class="admin-user-control-strip" aria-label="Admin user governance summary">
                    <button
                      v-for="filter in adminUserFilterRows"
                      :key="filter.key"
                      type="button"
                      :class="{ active: adminUserFilter === filter.key }"
                      @click="adminUserFilter = filter.key"
                    >
                      <strong>{{ filter.value }}</strong>
                      <small>{{ filter.label }}</small>
                    </button>
                  </div>
                  <div v-if="adminUserRows.length" class="admin-user-list">
                    <article v-for="row in adminUserRows" :key="row.id">
                      <span class="contributor-avatar">{{ initialsFor(row.name) }}</span>
                      <div>
                        <strong>{{ row.name }}</strong>
                        <small>{{ row.wallet }} / {{ row.budget }}</small>
                        <small>{{ row.email }} В· {{ row.github }}</small>
                      </div>
                      <b :class="row.roleTone">{{ row.role }}</b>
                      <small>{{ row.score }}/100 governance score</small>
                      <div class="admin-user-actions">
                        <button
                          type="button"
                          :disabled="adminUserUpdatingID === row.id || row.rawRole === 'admin'"
                          @click="updateAdminUserRole(row, 'admin')"
                        >
                          <ShieldCheck :size="12" />
                          Promote
                        </button>
                        <button
                          type="button"
                          :disabled="adminUserUpdatingID === row.id || row.rawRole !== 'admin'"
                          @click="updateAdminUserRole(row, 'client')"
                        >
                          <User :size="12" />
                          Set client
                        </button>
                        <button type="button" :disabled="adminUserUpdatingID === row.id" @click="copyAdminUserAudit(row)">
                          <Link2 :size="12" />
                          Copy audit
                        </button>
                      </div>
                      <small>{{ row.projects }} projects В· {{ row.risk }}</small>
                    </article>
                  </div>
                  <article v-else class="dash-empty-state compact">
                    <strong>No user rows</strong>
                    <p>Admin-visible account and worker risk rows will appear here.</p>
                  </article>
                </article>

                <article class="dash-card">
                  <div class="card-title-row">
                    <h2>Worker Reputation</h2>
                    <span>{{ adminReputationRows.length }}</span>
                  </div>
                  <div v-if="adminReputationRows.length" class="admin-reputation-list">
                    <article v-for="row in adminReputationRows" :key="row.id">
                      <div>
                        <strong>{{ row.worker }}</strong>
                        <small>{{ row.flags }}</small>
                      </div>
                      <span>{{ row.score }}</span>
                      <b>{{ row.risk }}</b>
                      <small>{{ row.tasks }} tasks В· {{ row.paid }}</small>
                    </article>
                  </div>
                  <article v-else class="dash-empty-state compact">
                    <strong>No worker audits</strong>
                    <p>Paid and claimed worker reputation rows will appear here.</p>
                  </article>
                </article>
              </section>
            </template>
          </template>

          <template v-else-if="dashboardSection === 'worker'">
            <div class="dash-breadcrumb">
              <Home :size="14" />
              <span>Worker</span>
              <ChevronDown :size="13" />
              <strong>{{ workerDashboardView.title }}</strong>
            </div>

            <section v-if="workerDashboardError" class="dash-empty-state">
              <strong>Could not load worker dashboard</strong>
              <p>{{ workerDashboardError }}</p>
              <button class="secondary-button compact" type="button" @click="loadWorkerDashboardData">Retry</button>
            </section>

            <template v-else>
              <section class="dash-project-header worker-dashboard-header">
                <div class="dash-project-title">
                  <span class="project-photo">{{ workerDashboardView.initials }}</span>
                  <div>
                    <h1>{{ workerDashboardView.title }}</h1>
                    <p>{{ workerDashboardView.body }}</p>
                  </div>
                  <span :class="['live-badge', dashboardStatusClass(workerDashboardView.status)]">{{ workerDashboardView.status }}</span>
                </div>

                <div class="dash-project-actions">
                  <button type="button" @click="loadWorkerDashboardData">
                    <RefreshCw :size="15" />
                    Refresh
                  </button>
                  <button type="button" @click="openPublicPage('marketplace')">
                    <UsersRound :size="15" />
                    Marketplace
                  </button>
                </div>
              </section>

              <section class="dash-metrics" aria-label="Worker summary">
                <article v-for="metric in workerDashboardMetrics" :key="metric.label">
                  <span>{{ metric.label }}</span>
                  <strong>{{ metric.value }}</strong>
                  <small>{{ metric.caption }}</small>
                </article>
              </section>

              <section class="worker-dashboard-grid">
                <article class="dash-card worker-reputation-card">
                  <div class="card-title-row">
                    <h2>Reputation</h2>
                    <span>{{ workerReputationScore }} / 100</span>
                  </div>
                  <div class="worker-score-ring" :style="workerScoreRingStyle">
                    <strong>{{ workerReputationScore }}</strong>
                    <span>Score</span>
                  </div>
                  <div class="risk-grid">
                    <span v-for="item in workerReputationRows" :key="item.label" :class="item.tone">
                      {{ item.label }}
                      <strong>{{ item.value }}</strong>
                    </span>
                  </div>
                </article>

                <article class="dash-card worker-identity-card">
                  <div class="card-title-row">
                    <h2>Identity</h2>
                    <span>{{ workerIdentityReadyCount }} ready</span>
                  </div>
                  <div class="worker-identity-list">
                    <article v-for="item in workerIdentityRows" :key="item.label">
                      <span :class="['notification-dot', item.ready ? 'green' : 'amber']" />
                      <div>
                        <strong>{{ item.label }}</strong>
                        <small>{{ item.value || 'Not linked' }}</small>
                      </div>
                      <b>{{ item.ready ? 'Ready' : 'Needed' }}</b>
                    </article>
                  </div>
                  <button class="rail-link-button" :disabled="authBusy || !githubOAuthReady" type="button" @click="startGitHubLogin">
                    Link GitHub
                  </button>
                </article>
              </section>

              <section class="dash-card worker-audit-card" aria-label="Worker reputation audit">
                <div class="card-title-row">
                  <div>
                    <h2>Reputation Audit</h2>
                    <p>Identity, payout proof, and risk signals for claim and release decisions.</p>
                  </div>
                  <span :class="['worker-audit-risk', workerAuditView.riskTone]">{{ workerAuditView.riskLabel }}</span>
                </div>
                <div class="worker-audit-layout">
                  <div class="worker-audit-score">
                    <span>Audit score</span>
                    <strong>{{ workerAuditView.score }}</strong>
                    <small>{{ workerAuditView.level }}</small>
                  </div>
                  <div class="worker-audit-copy">
                    <strong>{{ workerAuditView.worker }}</strong>
                    <p>{{ workerAuditView.summary }}</p>
                    <div class="worker-audit-status-row">
                      <span v-for="item in workerAuditIdentityRows" :key="item.label" :class="item.tone">
                        <b>{{ item.label }}</b>
                        <small>{{ item.value }}</small>
                      </span>
                    </div>
                  </div>
                  <div class="worker-audit-stats">
                    <article v-for="item in workerAuditStatRows" :key="item.label">
                      <span>{{ item.label }}</span>
                      <strong>{{ item.value }}</strong>
                      <small>{{ item.caption }}</small>
                    </article>
                  </div>
                </div>
                <div class="worker-audit-flags">
                  <span v-for="flag in workerAuditFlagRows" :key="flag.label" :class="flag.tone">
                    {{ flag.label }}
                  </span>
                </div>
              </section>

              <section class="dash-card live-pr-board">
                <div class="card-title-row">
                  <div>
                    <h2>Claimed Tasks</h2>
                    <p>Claimed, submitted, and paid work matched to your wallet or GitHub identity.</p>
                  </div>
                  <button type="button" @click="loadWorkerDashboardData">Refresh</button>
                </div>
                <div v-if="workerClaimedTaskRows.length" class="dash-pr-list">
                  <article v-for="task in workerClaimedTaskRows" :key="task.id" class="dash-pr-row">
                    <span class="contributor-avatar">{{ task.initials }}</span>
                    <div class="dash-pr-main">
                      <strong>#{{ task.issueNumber }} {{ task.title }}</strong>
                      <small>{{ task.acceptance }}</small>
                      <span>{{ task.project }}</span>
                    </div>
                    <div class="dash-pr-stat">
                      <strong>{{ task.reward }}</strong>
                      <small>Reward</small>
                    </div>
                    <div class="dash-pr-stat positive">
                      <strong>{{ task.kind }}</strong>
                      <small>Worker</small>
                    </div>
                    <div class="dash-pr-stat negative">
                      <strong>{{ task.when }}</strong>
                      <small>{{ task.whenLabel }}</small>
                    </div>
                    <div class="dash-pr-actions">
                      <b :class="task.statusTone">{{ task.status }}</b>
                      <a v-if="task.reviewURL" :href="task.reviewURL" target="_blank" rel="noreferrer">
                        <Link2 :size="12" />
                        Evidence
                      </a>
                      <a v-if="task.ledgerProofURL" :href="task.ledgerProofURL" target="_blank" rel="noreferrer">
                        <ShieldCheck :size="12" />
                        Proof
                      </a>
                      <button
                        v-if="task.canSubmitReview"
                        type="button"
                        :disabled="reviewSubmittingTaskID === task.id"
                        @click="toggleTaskReviewSubmission(task)"
                      >
                        <SendHorizontal :size="12" />
                        {{ task.reviewOpen ? 'Close' : 'Submit' }}
                      </button>
                    </div>
                    <form v-if="task.reviewOpen" class="task-review-panel" @submit.prevent="submitTaskReview(task)">
                      <div v-if="taskReviewErrorList(task).length" class="task-review-errors" role="alert">
                        <strong>Fix review evidence</strong>
                        <ul>
                          <li v-for="item in taskReviewErrorList(task)" :key="item.field">{{ item.message }}</li>
                        </ul>
                      </div>
                      <label :class="{ invalid: taskReviewFieldError(task, 'pullRequestURL') }">
                        <span>Pull request URL</span>
                        <input
                          v-model.trim="task.reviewDraft.pullRequestURL"
                          type="url"
                          :aria-invalid="Boolean(taskReviewFieldError(task, 'pullRequestURL'))"
                          placeholder="https://github.com/org/repo/pull/12"
                          @input="clearTaskReviewFieldError(task, 'pullRequestURL')"
                        />
                        <small v-if="taskReviewFieldError(task, 'pullRequestURL')">{{ taskReviewFieldError(task, 'pullRequestURL') }}</small>
                      </label>
                      <label :class="{ invalid: taskReviewFieldError(task, 'evidenceURL') }">
                        <span>Evidence URL</span>
                        <input
                          v-model.trim="task.reviewDraft.evidenceURL"
                          type="url"
                          :aria-invalid="Boolean(taskReviewFieldError(task, 'evidenceURL'))"
                          placeholder="https://preview.example.com/evidence"
                          @input="clearTaskReviewFieldError(task, 'evidenceURL')"
                        />
                        <small v-if="taskReviewFieldError(task, 'evidenceURL')">{{ taskReviewFieldError(task, 'evidenceURL') }}</small>
                      </label>
                      <label class="wide" :class="{ invalid: taskReviewFieldError(task, 'notes') }">
                        <span>Review notes</span>
                        <textarea
                          v-model.trim="task.reviewDraft.notes"
                          rows="3"
                          :aria-invalid="Boolean(taskReviewFieldError(task, 'notes'))"
                          placeholder="Tests, preview, deployment, and risk notes"
                          @input="clearTaskReviewFieldError(task, 'notes')"
                        ></textarea>
                        <small v-if="taskReviewFieldError(task, 'notes')">{{ taskReviewFieldError(task, 'notes') }}</small>
                      </label>
                      <button type="submit" :disabled="reviewSubmittingTaskID === task.id">
                        <SendHorizontal :size="13" />
                        {{ reviewSubmittingTaskID === task.id ? 'Submitting' : 'Submit review' }}
                      </button>
                    </form>
                  </article>
                </div>
                <article v-else class="dash-empty-state compact">
                  <strong>{{ workerDashboardLoading ? 'Loading claimed tasks...' : 'No claimed tasks yet' }}</strong>
                  <p>{{ workerDashboardLoading ? 'Matching tasks to your GitHub and wallet identities.' : 'Claim a marketplace bounty to start a reviewable task.' }}</p>
                  <div v-if="!workerDashboardLoading" class="dashboard-tool-empty-actions compact">
                    <button type="button" @click="openDashboardSection('bounties')">
                      <Compass :size="13" />
                      Open Bounties
                    </button>
                    <button type="button" @click="loadWorkerDashboardData">
                      <RefreshCw :size="13" />
                      Refresh
                    </button>
                  </div>
                </article>
              </section>

              <section class="worker-dashboard-grid">
                <article class="dash-card">
                  <div class="card-title-row">
                    <h2>Rewards</h2>
                    <span>{{ workerRewardRows.length }} rows</span>
                  </div>
                  <div v-if="workerRewardRows.length" class="worker-reward-list">
                    <article v-for="reward in workerRewardRows" :key="reward.key">
                      <div>
                        <strong>{{ reward.amount }}</strong>
                        <small>{{ reward.type }} В· {{ reward.when }}</small>
                      </div>
                      <a v-if="reward.ledgerProofURL" :href="reward.ledgerProofURL" target="_blank" rel="noreferrer">
                        Proof
                      </a>
                      <span v-else>{{ reward.ref }}</span>
                    </article>
                  </div>
                  <article v-else class="dash-empty-state compact">
                    <strong>No reward entries</strong>
                    <p>MRG task payouts and manual credits will be listed here.</p>
                    <div class="dashboard-tool-empty-actions compact">
                      <button type="button" @click="openPublicPage('ledger')">
                        <Link2 :size="13" />
                        Public Ledger
                      </button>
                      <button type="button" @click="loadWorkerDashboardData">
                        <RefreshCw :size="13" />
                        Refresh
                      </button>
                    </div>
