                        </button>
                        <button
                          type="button"
                          class="secondary"
                          :disabled="proposingBountyID === proposal.id || !proposal.canClaim"
                          @click="submitWorkerProposal(proposal)"
                        >
                          <SendHorizontal :size="13" />
