                        <Compass :size="13" />
                        Open Bounties
                      </button>
                      <button type="button" @click="openPublicPage('marketplace')">
                        <UsersRound :size="13" />
                        Marketplace
                      </button>
                    </div>
                  </article>
                  <div v-if="workerSubmittedProposalRows.length" class="worker-submitted-proposal-list" aria-label="Submitted worker proposals">
