                          :key="action.label"
                          type="button"
                          :disabled="action.disabled"
                          @click="action.run()"
                        >
                          <component :is="action.icon" :size="13" />
                          {{ action.label }}
                        </button>
                      </div>
                    </article>
                  </template>
