                      <button type="button" :disabled="dashboardIssueScannerPrimaryAction.disabled" @click="runDashboardIssueScannerAction">
                        <component :is="dashboardIssueScannerPrimaryAction.icon" :size="14" />
                        {{ dashboardIssueScannerPrimaryAction.label }}
                      </button>
                    </div>
