                        <p>{{ log.body }}</p>
                        <small>{{ log.source }}<template v-if="log.meta"> - {{ log.meta }}</template><template v-if="log.reference"> - {{ log.reference }}</template></small>
                      </div>
                      <b :class="log.tone">{{ log.status }}</b>
