              </button>
            </div>
            <div class="contracts-stat-grid">
              <article v-for="stat in contractsEconomyStats" :key="stat.label">
                <span :class="['ledger-trust-icon', stat.tone]">
                  <component :is="stat.icon" :size="15" />
                </span>
                <div>
                  <strong>{{ stat.value }}</strong>
                  <small>{{ stat.label }}</small>
                  <em>{{ stat.detail }}</em>
                </div>
              </article>
            </div>
          </aside>
        </section>

        <section class="contracts-architecture-grid" :aria-label="publicContractsCopy.architectureTitle">
          <article v-for="lane in contractsArchitectureRows" :key="lane.key">
            <div class="contracts-card-head">
              <span :class="['ledger-economy-icon', lane.tone]">
                <component :is="lane.icon" :size="17" />
              </span>
              <b>{{ lane.meta }}</b>
            </div>
            <strong>{{ lane.title }}</strong>
            <p>{{ lane.body }}</p>
            <small>{{ lane.value }}</small>
          </article>
        </section>

        <section class="contracts-content-grid">
          <div class="contracts-main-card">
            <div class="contracts-section-head">
              <div>
                <span class="marketplace-eyebrow">{{ publicContractsCopy.flowTitle }}</span>
                <h2>{{ publicContractsCopy.architectureTitle }}</h2>
                <p>{{ publicContractsCopy.architectureBody }}</p>
              </div>
              <span>{{ ledgerEconomyFlowRows.length }} {{ publicContractsCopy.rows }}</span>
            </div>

            <div v-if="ledgerLoading" class="live-feed-state">{{ publicContractsCopy.statusSyncing }}</div>
            <div v-else-if="ledgerError" class="live-feed-state error">{{ ledgerError }}</div>
            <div v-else class="contracts-lifecycle-list">
              <article v-for="step in contractsLifecycleRows" :key="step.key">
                <span class="contracts-lifecycle-index">{{ step.sequence }}</span>
                <span :class="['ledger-trust-icon', step.tone]">
                  <component :is="step.icon" :size="15" />
                </span>
                <div>
                  <strong>{{ step.title }}</strong>
                  <p>{{ step.body }}</p>
                  <small>{{ step.count }} {{ publicContractsCopy.events }} - {{ step.updated }}</small>
                </div>
                <b>{{ step.amount }}</b>
              </article>
            </div>
          </div>

          <aside class="contracts-proof-card">
            <div class="contracts-section-head compact">
              <div>
                <span class="marketplace-eyebrow">{{ publicContractsCopy.proofTitle }}</span>
                <h2>{{ ledgerProofSummary.label }}</h2>
              </div>
              <button type="button" @click="copyContractsProofPacket">
                {{ publicContractsCopy.copy }}
                <Link2 :size="12" />
              </button>
            </div>
            <p>{{ publicContractsCopy.proofBody }}</p>
            <div class="contracts-proof-list">
              <article v-for="row in contractsProofRows" :key="row.label">
                <span :class="['ledger-economy-mini-icon', row.tone]">
                  <component :is="row.icon" :size="14" />
                </span>
                <div>
                  <strong>{{ row.label }}</strong>
                  <small>{{ row.value }}</small>
                </div>
                <button type="button" @click="copyContractsProofRow(row)">
                  <Link2 :size="12" />
                </button>
              </article>
            </div>
          </aside>
        </section>

        <section class="contracts-ledger-grid">
          <article class="contracts-ledger-panel">
            <div class="contracts-section-head compact">
              <div>
                <span class="marketplace-eyebrow">{{ publicContractsCopy.reserveTitle }}</span>
                <h2>{{ publicContractsCopy.reserveTitle }}</h2>
              </div>
              <small>{{ contractsReserveRows.length }}</small>
            </div>
            <p>{{ publicContractsCopy.reserveBody }}</p>
            <div v-if="contractsReserveRows.length" class="contracts-row-list">
              <article v-for="row in contractsReserveRows" :key="row.id">
                <span :class="['ledger-economy-mini-icon', row.tone]">
                  <component :is="row.icon" :size="14" />
                </span>
                <div>
                  <strong>{{ row.label }}</strong>
                  <small>{{ row.role }} - {{ row.count }}</small>
                </div>
                <b>{{ row.amount }}</b>
              </article>
            </div>
            <div v-else class="live-feed-state">{{ publicContractsCopy.noRows }}</div>
          </article>

          <article class="contracts-ledger-panel">
            <div class="contracts-section-head compact">
              <div>
                <span class="marketplace-eyebrow">{{ publicContractsCopy.flowTitle }}</span>
                <h2>{{ publicContractsCopy.flowTitle }}</h2>
              </div>
              <small>{{ ledgerEconomyFlowRows.length }}</small>
            </div>
            <p>{{ publicContractsCopy.flowBody }}</p>
            <div v-if="ledgerEconomyFlowRows.length" class="contracts-row-list">
              <article v-for="row in ledgerEconomyFlowRows" :key="row.type">
                <span :class="['ledger-economy-mini-icon', row.tone]">
                  <component :is="row.icon" :size="14" />
                </span>
                <div>
                  <strong>{{ row.label }}</strong>
                  <small>{{ row.countLabel }} - #{{ row.latestSequence }}</small>
                </div>
                <b>{{ row.amount }}</b>
              </article>
            </div>
            <div v-else class="live-feed-state">{{ publicContractsCopy.noRows }}</div>
          </article>

          <article class="contracts-ledger-panel">
            <div class="contracts-section-head compact">
              <div>
                <span class="marketplace-eyebrow">{{ publicContractsCopy.recentTitle }}</span>
                <h2>{{ publicContractsCopy.recentTitle }}</h2>
              </div>
              <button type="button" @click="openPublicPage('ledger')">
                {{ publicContractsCopy.openLedger }}
                <ArrowRight :size="12" />
              </button>
            </div>
            <p>{{ publicContractsCopy.recentBody }}</p>
            <div v-if="contractsRecentAnchors.length" class="contracts-row-list">
              <article v-for="row in contractsRecentAnchors" :key="row.key">
                <span :class="['ledger-economy-mini-icon', row.tone]">
                  <component :is="row.icon" :size="14" />
                </span>
                <div>
                  <strong>{{ row.label }}</strong>
                  <small>{{ row.reference }} - {{ row.when }}</small>
                </div>
                <button type="button" @click="copyLedgerReference(row.hash)">
                  {{ row.shortHash }}
                </button>
              </article>
            </div>
            <div v-else class="live-feed-state">{{ publicContractsCopy.noRows }}</div>
          </article>
        </section>
      </div>
    </main>

    <main v-else-if="publicTokenPage" id="top" class="token-page" :class="`token-page-${publicPage}`">
      <div class="home-container token-shell">
        <section class="token-hero">
          <div class="token-hero-copy">
            <span class="marketplace-eyebrow">{{ publicTokenPage.eyebrow }}</span>
            <div class="ledger-title-row">
              <h1>{{ publicTokenPage.title }}</h1>
              <span :class="['ledger-public-badge', publicTokenPage.badgeTone]">
                <component :is="publicTokenPage.badgeIcon" :size="14" />
                {{ publicTokenPage.badge }}
              </span>
            </div>
            <p>{{ publicTokenPage.body }}</p>
            <div class="marketplace-actions">
              <template v-for="action in publicTokenPage.actions" :key="action.label">
                <a
                  v-if="action.command === 'token-launch-brief'"
                  :class="[action.primary ? 'primary-button' : 'secondary-button', 'large']"
                  href="#token-ceo-brief"
                  @click="handlePublicAction(action)"
                >
                  {{ action.label }}
                  <component :is="action.icon" :size="16" />
                </a>
                <button
                  v-else
                  :class="[action.primary ? 'primary-button' : 'secondary-button', 'large']"
                  type="button"
                  @click="handlePublicAction(action)"
                >
                  {{ action.label }}
                  <component :is="action.icon" :size="16" />
                </button>
              </template>
            </div>
            <div v-if="publicPage === 'airdrop' || publicPage === 'presale'" class="token-hero-gate-note" aria-label="CEO launch gate order">
              <span>
                <Search :size="13" />
                CEO reviews candidate first
              </span>
              <span>
                <ShieldCheck :size="13" />
                {{ publicPage === 'airdrop' ? 'Claims open after proof gate' : 'Reservations open after funding gate' }}
              </span>
            </div>
            <div v-if="publicPage === 'airdrop' || publicPage === 'presale'" class="token-hero-ceo-strip" aria-label="CEO launch research summary">
              <article v-for="row in tokenCeoQueueStatRows" :key="row.label">
                <small>{{ row.label }}</small>
                <strong>{{ row.value }}</strong>
              </article>
            </div>
          </div>

          <aside class="token-status-panel" :aria-label="publicTokenPage.panelTitle">
            <div class="ledger-card-head">
              <div>
                <span>{{ publicTokenPage.panelEyebrow }}</span>
                <h2>{{ publicTokenPage.panelTitle }}</h2>
              </div>
              <button type="button" aria-label="Refresh token proof data" :disabled="ledgerLoading" @click="refreshTokenPageData">
                <RefreshCw :class="{ 'loading-spin': ledgerLoading }" :size="14" />
                Refresh
              </button>
            </div>
            <p>{{ publicTokenPage.panelBody }}</p>
            <div class="token-metric-grid">
              <article v-for="metric in publicTokenMetricRows" :key="metric.label">
                <span :class="['ledger-economy-mini-icon', metric.tone]">
                  <component :is="metric.icon" :size="14" />
                </span>
                <div>
                  <strong>{{ metric.value }}</strong>
                  <small>{{ metric.label }}</small>
                </div>
              </article>
            </div>
          </aside>
        </section>

        <section v-if="publicPage === 'airdrop' || publicPage === 'presale'" class="token-ceo-research-panel" aria-labelledby="token-ceo-research-title">
          <div class="token-ceo-research-head">
            <span class="public-card-icon purple">
              <Search :size="18" />
            </span>
            <div>
              <span class="marketplace-eyebrow">CEO LAUNCH DECISION</span>
              <h2 id="token-ceo-research-title">{{ tokenCeoResearchCopy.title }}</h2>
              <p>{{ tokenCeoResearchCopy.body }}</p>
            </div>
            <div class="token-ceo-head-actions">
              <b>{{ tokenCeoResearchCopy.readiness }}</b>
              <a :href="tokenCeoCandidatesURL" target="_blank" rel="noreferrer">
                Candidate source
                <Link2 :size="11" />
              </a>
              <a :href="tokenCeoQueueURL" target="_blank" rel="noreferrer">
                Memo ledger
                <Link2 :size="11" />
              </a>
            </div>
          </div>
          <div class="token-ceo-decision-strip" aria-label="CEO launch decision stages">
            <article v-for="row in tokenCeoDecisionRows" :key="row.label">
              <span>{{ row.label }}</span>
              <strong>{{ row.value }}</strong>
            </article>
          </div>
          <div class="token-ceo-queue-stats" aria-label="Public CEO research queue stats">
            <article v-for="row in tokenCeoQueueStatRows" :key="row.label">
              <small>{{ row.label }}</small>
              <strong>{{ row.value }}</strong>
            </article>
          </div>
          <div v-if="tokenCeoCandidateRows.length" class="token-ceo-candidate-lane" aria-label="CEO candidate projects">
            <article v-for="row in tokenCeoCandidateRows" :key="row.key">
              <span :class="['ledger-trust-icon', row.tone]">
                <Compass :size="14" />
              </span>
              <div>
                <small>
                  {{ row.label }}
                  <b v-if="row.scoreLabel">{{ row.scoreLabel }}</b>
                </small>
                <strong>{{ row.title }}</strong>
                <p>{{ row.body }}</p>
                <div v-if="row.verdict" :class="['token-ceo-candidate-verdict', row.verdict.tone]" aria-label="CEO launch verdict">
                  <b>{{ row.verdict.label }}</b>
                  <span>{{ row.verdict.reason }}</span>
                </div>
                <div v-if="row.readinessRows?.length" class="token-ceo-candidate-gate-strip" aria-label="CEO launch gate summary">
                  <span v-for="gate in row.readinessRows" :key="gate.label" :class="gate.state">
                    <b>{{ gate.label }}</b>
                    <small>{{ gate.state }}</small>
                  </span>
                </div>
                <em v-if="row.decisionPreview?.nextAction" class="token-ceo-candidate-next-action">
                  {{ row.decisionPreview.nextAction }}
                </em>
                <details
                  v-if="row.contextRows?.length || row.proofSignalRows?.length || row.readinessRows?.length || row.decisionPreview"
                  class="token-ceo-candidate-proof"
                >
                  <summary>
                    Proof packet
                    <ChevronDown :size="12" />
                  </summary>
                  <div v-if="row.contextRows?.length" class="token-ceo-candidate-context" role="group" aria-label="CEO launch brief context">
                    <span v-for="item in row.contextRows" :key="item.label">
                      <b>{{ item.label }}</b>
                      <small>{{ item.value }}</small>
                    </span>
                  </div>
                  <div v-if="row.proofSignalRows?.length" class="token-ceo-candidate-signals" aria-label="CEO proof signals">
                    <span v-for="signal in row.proofSignalRows" :key="signal">{{ signal }}</span>
                    <b v-if="row.proofSignalExtra">+{{ row.proofSignalExtra }}</b>
                  </div>
                  <div v-if="row.readinessRows?.length" class="token-ceo-candidate-readiness" aria-label="CEO readiness gates">
                    <span v-for="gate in row.readinessRows" :key="gate.label" :class="gate.state">
                      <b>{{ gate.label }}</b>
                      <small>{{ gate.value }}</small>
                    </span>
                  </div>
                  <div v-if="row.decisionPreview" class="token-ceo-candidate-policy">
                    <b>{{ row.decisionPreview.label }}</b>
                    <span>{{ row.decisionPreview.proofPolicy }}</span>
                    <em v-if="row.decisionPreview.nextAction">{{ row.decisionPreview.nextAction }}</em>
                    <small>{{ row.decisionPreview.riskNotes }}</small>
                  </div>
                </details>
              </div>
              <div class="token-ceo-candidate-actions">
                <a v-if="row.sourceUrl" :href="row.sourceUrl" target="_blank" rel="noreferrer">
                  Source
                  <Link2 :size="10" />
                </a>
                <button type="button" @click="prefillTokenLaunchBriefFromCandidate(row)">
                  Use for CEO brief
                  <ArrowRight :size="10" />
                </button>
              </div>
              <div class="token-ceo-candidate-decisions" aria-label="CEO candidate decision actions">
                <button
                  v-for="decision in row.decisionRows"
                  :key="decision.key"
                  :class="decision.tone"
                  type="button"
                  @click="applyTokenLaunchCandidateDecision(row, decision)"
                >
                  {{ decision.label }}
                </button>
              </div>
            </article>
          </div>
          <article v-else class="token-ceo-candidate-empty" aria-label="CEO candidate queue status">
            <span class="ledger-trust-icon purple">
              <Compass :size="14" />
            </span>
            <div>
              <small>{{ tokenCeoCandidateEmptyCopy.eyebrow }}</small>
              <strong>{{ tokenCeoCandidateEmptyCopy.title }}</strong>
              <p>{{ tokenCeoCandidateEmptyCopy.body }}</p>
              <div v-if="tokenCeoCandidateEmptyCopy.checks?.length" class="token-ceo-empty-gates" aria-label="CEO candidate qualification gates">
                <span v-for="check in tokenCeoCandidateEmptyCopy.checks" :key="check">{{ check }}</span>
              </div>
            </div>
            <div class="token-ceo-candidate-empty-actions">
              <button type="button" @click="openTokenLaunchBriefFromProofBoard">
                Open CEO brief
                <ArrowRight :size="11" />
              </button>
              <a :href="tokenCeoCandidatesURL" target="_blank" rel="noreferrer">
                Review data
                <Link2 :size="10" />
              </a>
            </div>
          </article>
          <div v-if="tokenCeoLiveQueueRows.length" class="token-ceo-live-queue" aria-label="Live CEO memo queue">
            <article v-for="row in tokenCeoLiveQueueRows" :key="row.key">
              <span :class="['ledger-trust-icon', row.tone]">
                <FileCheck2 :size="14" />
              </span>
              <div>
                <small>{{ row.label }}</small>
                <strong>{{ row.title }}</strong>
                <p>{{ row.summary }}</p>
                <div v-if="row.contextRows?.length" class="token-ceo-live-context" role="group" aria-label="CEO memo policy context">
                  <span v-for="item in row.contextRows" :key="item.label">
                    <b>{{ item.label }}</b>
                    <small>{{ item.value }}</small>
                  </span>
                </div>
              </div>
              <div class="token-ceo-live-actions">
                <a :href="row.proofUrl" target="_blank" rel="noreferrer">
                  Proof
                  <Link2 :size="10" />
                </a>
                <a v-if="row.sourceUrl" :href="row.sourceUrl" target="_blank" rel="noreferrer">
                  Source
                  <Link2 :size="10" />
                </a>
              </div>
            </article>
          </div>
          <article v-else class="token-ceo-live-empty" aria-label="Empty CEO memo queue">
            <span class="ledger-trust-icon purple">
              <FileCheck2 :size="14" />
            </span>
            <div>
              <small>Live CEO queue</small>
              <strong>{{ tokenCeoLiveEmptyCopy.title }}</strong>
              <p>{{ tokenCeoLiveEmptyCopy.body }}</p>
            </div>
            <button type="button" @click="openTokenLaunchBriefFromProofBoard">
              Open CEO brief
              <ArrowRight :size="11" />
            </button>
          </article>
          <details class="token-ceo-proof-drawer">
            <summary>
              CEO source packet
              <ChevronDown :size="13" />
            </summary>
            <div class="token-ceo-source-packet" aria-label="CEO research packet">
              <article v-for="row in tokenCeoSourcePacketRows" :key="row.label">
                <span :class="['ledger-trust-icon', row.tone]">
                  <component :is="row.icon" :size="14" />
                </span>
                <div>
                  <small>{{ row.label }}</small>
                  <strong>{{ row.value }}</strong>
                </div>
              </article>
            </div>
            <div class="token-ceo-project-queue" aria-label="CEO project research queue">
              <article v-for="row in tokenCeoProjectResearchRows" :key="row.title">
                <span :class="['ledger-trust-icon', row.tone]">
                  <component :is="row.icon" :size="15" />
                </span>
                <div>
                  <strong>{{ row.title }}</strong>
                  <small>{{ row.body }}</small>
                </div>
                <b>{{ row.status }}</b>
              </article>
            </div>
            <div class="token-ceo-research-grid">
              <article v-for="row in tokenCeoResearchRows" :key="row.title">
                <span :class="['ledger-trust-icon', row.tone]">
                  <component :is="row.icon" :size="15" />
                </span>
                <div>
                  <strong>{{ row.title }}</strong>
                  <p>{{ row.body }}</p>
                  <small>{{ row.evidence }}</small>
                </div>
              </article>
            </div>
          </details>
          <details id="token-ceo-brief" class="token-ceo-brief-drawer">
            <summary>
              <span>
                <FileCheck2 :size="14" />
                CEO brief intake
              </span>
              <b>{{ tokenCeoLaunchBriefCopy.launchTypeLabel }}</b>
              <ChevronDown :size="13" />
            </summary>
          <form class="token-ceo-brief-card" @submit.prevent="submitTokenLaunchBrief">
            <div class="token-ceo-brief-copy">
              <span class="marketplace-eyebrow">{{ tokenCeoLaunchBriefCopy.eyebrow }}</span>
              <strong>{{ tokenCeoLaunchBriefCopy.title }}</strong>
              <p>{{ tokenCeoLaunchBriefCopy.body }}</p>
              <div class="token-ceo-launch-context" aria-label="CEO launch brief context">
                <span>
                  <b>Launch type</b>
                  {{ tokenCeoLaunchBriefCopy.launchTypeLabel }}
                </span>
                <span>
                  <b>Ledger memo</b>
                  {{ tokenCeoLaunchBriefCopy.ledgerMemo }}
                </span>
              </div>
              <div class="token-ceo-signal-chips" aria-label="CEO research signals attached">
                <span v-for="signal in tokenCeoResearchSignalRows" :key="signal">{{ toTitleLabel(signal) }}</span>
              </div>
              <div class="token-ceo-brief-gates" aria-label="CEO brief required gates">
                <span v-for="gate in tokenCeoLaunchBriefCopy.quickGates" :key="gate">{{ gate }}</span>
              </div>
              <div v-if="tokenLaunchBriefDecisionContext.label" class="token-ceo-decision-context" aria-label="Loaded CEO decision">
                <b>{{ tokenLaunchBriefDecisionContext.label }}</b>
                <span>{{ tokenLaunchBriefDecisionContext.candidate }}</span>
                <small>{{ tokenLaunchBriefDecisionContext.score }}</small>
              </div>
            </div>
            <div v-if="tokenLaunchBriefAttempted && tokenLaunchBriefValidationRows.length" class="wizard-validation-banner token-workflow-validation" role="alert">
              <strong>Fix CEO brief</strong>
              <ul>
                <li v-for="item in tokenLaunchBriefValidationRows" :key="item.field">{{ item.message }}</li>
              </ul>
            </div>
            <div class="token-ceo-brief-form">
              <label class="wizard-field" :class="{ invalid: tokenLaunchBriefFieldError('project_title') }">
                <span>Project title <b>*</b></span>
                <input v-model.trim="tokenLaunchBriefForm.project_title" :disabled="tokenLaunchBriefBusy" maxlength="120" autocomplete="off" placeholder="Project or repo name" />
                <p v-if="tokenLaunchBriefFieldError('project_title')" class="wizard-field-error">{{ tokenLaunchBriefFieldError('project_title') }}</p>
              </label>
              <label class="wizard-field token-ceo-research-url-field" :class="{ invalid: tokenLaunchBriefFieldError('repository_url') }">
                <span>Research URL <b>*</b></span>
                <input v-model.trim="tokenLaunchBriefForm.repository_url" :disabled="tokenLaunchBriefBusy" autocomplete="off" :placeholder="tokenCeoLaunchBriefCopy.urlPlaceholder" />
                <small class="wizard-field-hint">{{ tokenCeoLaunchBriefCopy.urlHint }}</small>
                <p v-if="tokenLaunchBriefFieldError('repository_url')" class="wizard-field-error">{{ tokenLaunchBriefFieldError('repository_url') }}</p>
              </label>
              <label class="wizard-field full" :class="{ invalid: tokenLaunchBriefFieldError('project_summary') }">
                <span>CEO research brief <b>*</b></span>
                <textarea v-model.trim="tokenLaunchBriefForm.project_summary" :disabled="tokenLaunchBriefBusy" maxlength="420" rows="3" :placeholder="tokenCeoLaunchBriefCopy.summaryPlaceholder" />
                <p v-if="tokenLaunchBriefFieldError('project_summary')" class="wizard-field-error">{{ tokenLaunchBriefFieldError('project_summary') }}</p>
              </label>
              <label class="wizard-field" :class="{ invalid: tokenLaunchBriefFieldError('proof_policy') }">
                <span>Proof policy <b>*</b></span>
                <input v-model.trim="tokenLaunchBriefForm.proof_policy" :disabled="tokenLaunchBriefBusy" maxlength="180" autocomplete="off" :placeholder="tokenCeoLaunchBriefCopy.proofPlaceholder" />
                <p v-if="tokenLaunchBriefFieldError('proof_policy')" class="wizard-field-error">{{ tokenLaunchBriefFieldError('proof_policy') }}</p>
              </label>
              <label class="wizard-field">
                <span>{{ publicPage === 'airdrop' ? 'Allocation policy' : 'Reserve policy' }}</span>
                <input v-model.trim="tokenLaunchBriefForm.allocation_policy" :disabled="tokenLaunchBriefBusy" maxlength="180" autocomplete="off" :placeholder="tokenCeoLaunchBriefCopy.allocationPlaceholder" />
              </label>
              <label class="wizard-field" :class="{ invalid: tokenLaunchBriefFieldError('wallet_policy') }">
                <span>Wallet policy <b>*</b></span>
                <input v-model.trim="tokenLaunchBriefForm.wallet_policy" :disabled="tokenLaunchBriefBusy" maxlength="180" autocomplete="off" :placeholder="tokenCeoLaunchBriefCopy.walletPlaceholder" />
                <p v-if="tokenLaunchBriefFieldError('wallet_policy')" class="wizard-field-error">{{ tokenLaunchBriefFieldError('wallet_policy') }}</p>
              </label>
              <label class="wizard-field" :class="{ invalid: tokenLaunchBriefFieldError('risk_notes') }">
                <span>CEO risk notes <b>*</b></span>
                <input v-model.trim="tokenLaunchBriefForm.risk_notes" :disabled="tokenLaunchBriefBusy" maxlength="180" autocomplete="off" :placeholder="tokenCeoLaunchBriefCopy.riskPlaceholder" />
                <p v-if="tokenLaunchBriefFieldError('risk_notes')" class="wizard-field-error">{{ tokenLaunchBriefFieldError('risk_notes') }}</p>
              </label>
            </div>
            <p v-if="tokenLaunchBriefError" class="modal-error token-workflow-error">{{ tokenLaunchBriefError }}</p>
