                  <p>{{ row.body }}</p>
                  <small>{{ row.meta }}</small>
                </div>
                <b>{{ row.status }}</b>
              </li>
            </ol>
          </div>

          <aside class="token-proof-panel">
            <div class="contracts-section-head compact">
              <div>
