            </div>
            <div class="ledger-live-grid">
              <article v-for="stat in liveFeedStats" :key="stat.label">
                <strong>{{ stat.value }}</strong>
                <span>{{ stat.label }}</span>
              </article>
            </div>
            <button type="button" @click="loadLiveFeedData">
              <RefreshCw :size="14" />
