              <span class="marketplace-eyebrow">AI WORKFLOW TRACE</span>
              <h2 id="live-workflow-trace-title">Every live event mapped to the delivery workflow</h2>
              <p>Follow repository intake, AI scan, task generation, reward estimate, routing, PR review, deployment validation, and payout proof from one realtime surface.</p>
            </div>
            <button type="button" @click="copyLiveWorkflowTraceIndex">
              Copy trace
              <Link2 :size="12" />
            </button>
          </div>
          <div class="live-workflow-trace-grid">
            <article v-for="row in liveFeedWorkflowTraceRows" :key="row.key" :class="{ waiting: !row.count }">
              <div class="live-workflow-trace-top">
                <span :class="['live-feed-signal-index', row.tone]">{{ row.sequence }}</span>
                <div>
                  <small>{{ row.phase }}</small>
                  <strong>{{ row.title }}</strong>
                </div>
                <b :class="row.statusTone">{{ row.status }}</b>
              </div>
              <p>{{ row.body }}</p>
              <div class="live-workflow-trace-latest">
                <span :class="['ledger-trust-icon', row.tone]">
                  <component :is="row.icon" :size="15" />
                </span>
                <div>
                  <strong>{{ row.latestTitle }}</strong>
                  <small>{{ row.latestMeta }}</small>
                </div>
              </div>
              <dl class="live-workflow-trace-meta">
                <div>
                  <dt>Schema</dt>
                  <dd>{{ row.schema }}</dd>
                </div>
                <div>
                  <dt>Source</dt>
                  <dd>{{ row.sourceLabel }}</dd>
                </div>
                <div>
                  <dt>Proof</dt>
                  <dd>{{ row.proofLabel }}</dd>
                </div>
              </dl>
              <button type="button" :disabled="!row.count" @click="setLiveFeedType(row.filterLabel)">
                {{ row.actionLabel }}
                <ArrowRight :size="12" />
              </button>
            </article>
          </div>
        </section>

        <section id="live-event-contracts" class="live-event-contract-panel" aria-labelledby="live-event-contracts-title">
          <div class="live-event-contract-head">
            <div>
              <span class="marketplace-eyebrow">REALTIME EVENT CONTRACTS</span>
              <h2 id="live-event-contracts-title">Schema, source, and proof for every live signal</h2>
              <p>Map PRs, deployments, AI actions, and payouts to protocol versions, public endpoints, and ledger references.</p>
            </div>
            <button type="button" @click="copyLiveEventContractIndex">
              Copy matrix
              <Link2 :size="12" />
            </button>
          </div>
          <div class="live-event-contract-list">
            <article v-for="contract in liveFeedEventContractRows" :key="contract.key">
              <div class="live-event-contract-top">
                <span :class="['ledger-trust-icon', contract.tone]">
                  <component :is="contract.icon" :size="15" />
                </span>
                <div>
                  <strong>{{ contract.title }}</strong>
                  <small>{{ contract.version }}</small>
                </div>
                <b :class="contract.statusTone">{{ contract.status }}</b>
              </div>
              <p>{{ contract.body }}</p>
              <dl class="live-event-contract-meta">
                <div>
                  <dt>Schema</dt>
                  <dd>{{ contract.schema }}</dd>
                </div>
                <div>
                  <dt>Source</dt>
                  <dd>{{ contract.sourceLabel }}</dd>
                </div>
                <div>
                  <dt>Proof</dt>
                  <dd>{{ contract.proofLabel }}</dd>
                </div>
              </dl>
              <div class="live-event-contract-actions">
                <button type="button" :disabled="!contract.filterLabel" @click="setLiveFeedType(contract.filterLabel)">
                  {{ contract.filterActionLabel }}
                  <ArrowRight :size="12" />
                </button>
                <button type="button" @click="copyLiveEventContract(contract)">
                  Copy ref
                  <Link2 :size="12" />
                </button>
              </div>
            </article>
          </div>
        </section>

        <section class="live-feed-content">
          <div class="ledger-main-card live-feed-main-card">
            <div class="live-feed-toolbar">
              <div>
                <span class="marketplace-eyebrow">PUBLIC TIMELINE</span>
                <h2>Delivery activity</h2>
                <p class="live-feed-result-label">{{ liveFeedResultLabel }}</p>
              </div>
              <div class="ledger-table-actions">
                <button type="button" @click="loadLiveFeedData">
                  <RefreshCw :size="14" />
                  Refresh
                </button>
                <button type="button" @click="openPublicPage('ledger')">
                  Ledger Logs
                  <ArrowRight :size="13" />
                </button>
              </div>
            </div>

            <div v-if="liveFeedLoading" class="live-feed-state">Loading public activity...</div>
            <div v-else-if="liveFeedError" class="live-feed-state error">{{ liveFeedError }}</div>
            <div v-else-if="!liveFeedAllItemsView.length" class="live-feed-state">No live activity yet. Fund a project to create the first public events.</div>
            <div v-else-if="!liveFeedItemsView.length" class="live-feed-state">No live activity matches this filter.</div>
            <div v-else class="live-feed-list">
              <article v-for="item in liveFeedItemsView" :key="item.id" :class="['live-feed-row', { 'has-agent-packet': item.hasAgentPacket }]">
                <span :class="['ledger-event-type', item.tone]">
                  <component :is="item.icon" :size="15" />
                  {{ item.typeLabel }}
                </span>
                <div class="live-feed-row-copy">
                  <div>
                    <strong>{{ item.title }}</strong>
                    <span>{{ item.status }}</span>
                  </div>
                  <p>{{ item.body }}</p>
                  <small>{{ item.project }} В· {{ item.actor }} В· {{ item.meta }}<template v-if="item.delegationSummary"> В· {{ item.delegationSummary }}</template><template v-if="item.auditLabel"> В· {{ item.auditLabel }}</template></small>
                </div>
                <div class="live-feed-row-meta">
                  <strong v-if="item.amount" :class="['ledger-amount', item.amountTone]">{{ item.amount }}</strong>
                  <span v-else>{{ item.date }}</span>
                  <div v-if="item.url || item.rawReference || item.rawContractReference" class="ledger-ref-actions">
                    <button v-if="item.url || item.rawReference" class="ledger-ref-button" type="button" @click="handleLiveFeedReference(item)">
                      {{ item.reference || (item.url ? 'Open proof' : 'Copy ref') }}
                      <Link2 :size="12" />
                    </button>
                    <button v-if="item.rawContractReference" class="ledger-ref-button contract-ref-button" type="button" @click="copyContractReference(item)">
                      {{ item.contractReference }}
                      <Hash :size="12" />
                    </button>
                  </div>
                </div>
                <details v-if="item.hasAgentPacket" class="live-feed-agent-packet">
                  <summary>
                    <span>
                      <Bot :size="13" />
                      Agent packet
                    </span>
                    <small>{{ item.packetSummary }}</small>
                    <ChevronDown :size="13" />
                  </summary>
                  <div class="live-feed-agent-packet-body">
                    <div class="live-feed-agent-stats" aria-label="Agent packet summary">
                      <span>
                        <small>Context</small>
                        <strong>{{ item.packetCounts.context }}</strong>
                      </span>
                      <span>
                        <small>Runbook</small>
                        <strong>{{ item.packetCounts.runbook }}</strong>
                      </span>
                      <span>
                        <small>Evidence</small>
                        <strong>{{ item.packetCounts.evidence }}</strong>
                      </span>
                      <span>
                        <small>Checks</small>
                        <strong>{{ item.packetCounts.checks }}</strong>
                      </span>
                    </div>

                    <div class="live-feed-agent-packet-actions" aria-label="Agent packet actions">
                      <button type="button" @click="openLiveFeedAgentQueue(item)">
                        <Bot :size="13" />
                        Open in Agent Queue
                      </button>
                      <button type="button" @click="openLiveFeedMergeIDE(item)">
                        <Code2 :size="13" />
                        Open in MergeIDE
                      </button>
                    </div>

                    <div v-if="item.delegationChain.length" class="live-feed-agent-chain" aria-label="Agent delegation chain">
                      <span v-for="(agent, index) in item.delegationChain" :key="`${item.id}:agent-chain:${agent}:${index}`">
                        <b>{{ index + 1 }}</b>
                        {{ toTitleLabel(agent) }}
                      </span>
                    </div>

                    <div class="live-feed-agent-packet-grid">
                      <section v-if="item.packetContextRows.length" aria-label="Agent context URLs">
                        <strong>Context URLs</strong>
                        <div class="live-feed-agent-context-row">
                          <a
                            v-for="row in item.packetContextRows"
                            :key="row.key"
                            :href="row.href"
                            target="_blank"
                            rel="noreferrer"
                          >
                            {{ row.label }}
                            <small>{{ row.short }}</small>
                            <ExternalLink :size="11" />
                          </a>
                        </div>
                      </section>

                      <section v-if="item.packetRunbookRows.length" aria-label="Agent runbook">
                        <strong>Runbook</strong>
                        <ol class="live-feed-agent-runbook">
                          <li v-for="step in item.packetRunbookRows" :key="step.key">
                            <b>{{ step.step }}</b>
                            <span>{{ step.label }}</span>
                          </li>
                        </ol>
                      </section>

                      <section v-if="item.packetCheckRows.length" aria-label="Agent checks">
                        <strong>Checks</strong>
                        <div class="live-feed-agent-checks">
                          <article v-for="check in item.packetCheckRows" :key="check.key" :class="check.tone">
                            <span>{{ check.status }}</span>
                            <b>{{ check.name }}</b>
                            <small v-if="check.summary">{{ check.summary }}</small>
                            <a v-if="check.href" :href="check.href" target="_blank" rel="noreferrer">
                              Proof
                              <ExternalLink :size="10" />
                            </a>
                          </article>
                        </div>
                      </section>

                      <section v-if="item.packetEvidenceRows.length" aria-label="Agent evidence">
                        <strong>Evidence</strong>
                        <div class="live-feed-agent-evidence">
                          <span v-for="evidence in item.packetEvidenceRows" :key="evidence.key">
                            <CheckCircle2 :size="12" />
                            {{ evidence.label }}
                          </span>
                        </div>
                      </section>
                    </div>
                  </div>
                </details>
              </article>
            </div>
          </div>

          <aside class="ledger-rail">
            <section class="ledger-side-card">
              <div class="side-card-head">
                <h2>Activity Types</h2>
                <button type="button" @click="loadLiveFeedData">Refresh</button>
              </div>
              <div class="live-feed-type-list">
                <button
                  v-for="row in liveFeedTypeOptions"
                  :key="row.label"
                  :class="{ active: activeLiveFeedType === row.label }"
                  type="button"
                  @click="setLiveFeedType(row.label)"
                >
                  <span :class="['notification-dot', row.tone]" />
                  <strong>{{ row.label }}</strong>
                  <small>{{ row.count }}</small>
                </button>
                <article v-if="!liveFeedAllItemsView.length">
                  <span class="notification-dot blue" />
                  <strong>Waiting for events</strong>
                  <small>0</small>
                </article>
              </div>
            </section>

            <section class="ledger-side-card">
              <div class="side-card-head">
                <h2>Active Contributors</h2>
                <button type="button" @click="openPublicPage('marketplace')">Directory</button>
              </div>
              <div v-if="liveFeedContributorRows.length" class="live-contributor-list">
                <article v-for="contributor in liveFeedContributorRows" :key="contributor.key">
                  <span :class="['market-avatar', 'small', contributor.tone]">{{ contributor.initials }}</span>
                  <div>
                    <div class="live-contributor-topline">
                      <strong>{{ contributor.name }}</strong>
                      <span :class="['live-contributor-status', contributor.statusTone]">{{ contributor.status }}</span>
                    </div>
                    <p>{{ contributor.role }}</p>
                    <small>{{ contributor.meta }}</small>
                  </div>
                </article>
              </div>
              <p v-else class="live-feed-empty-copy">Accepted contributors will appear as the feed records work.</p>
            </section>

            <section class="ledger-side-card">
              <h2>Latest Signal</h2>
              <div v-if="liveFeedLatestProject" class="live-feed-latest">
                <span :class="['ledger-project-logo', liveFeedLatestProject.tone]">{{ projectInitialFor(liveFeedLatestProject.project) }}</span>
                <div>
                  <strong>{{ liveFeedLatestProject.title }}</strong>
                  <p>{{ liveFeedLatestProject.body }}</p>
                  <small>{{ liveFeedLatestProject.meta }}</small>
                </div>
              </div>
              <p v-else class="live-feed-empty-copy">No current signal.</p>
            </section>
          </aside>
        </section>
      </div>
