function tokenCeoResearchSourceLabel(source = '') {
  const raw = String(source || '').trim();
  if (!raw) return 'Public source pending';
  try {
    const url = new URL(raw);
    return url.hostname.replace(/^www\./, '') || raw;
  } catch {
    return raw.slice(0, 64);
  }
}
