  if (proofURL && !tokenWorkflowURLIsValid(proofURL)) errors.proof_url = 'Proof URL must start with http:// or https://.';
  if (String(airdropClaimForm.worker_id || '').trim().length > 160) errors.worker_id = 'Worker ID is too long.';
