      actionNoun: 'payouts',
    },
  ];

  return definitions.map((lane) => {
    const rows = liveFeedAllItemsView.value.filter((item) => liveFeedLaneMatches(item, lane));
    const latest = rows[0];
    const filterLabel = latest?.typeLabel || lane.fallbackFilter;
    return {
      ...lane,
      actionLabel: `${rows.length ? 'View' : 'Open'} ${lane.actionNoun}`,
      ariaLabel: `${rows.length ? 'View' : 'Open'} ${lane.title} lane`,
      countLabel: `${rows.length} event${rows.length === 1 ? '' : 's'}`,
      filterLabel,
      latestLabel: latest ? `${latest.project} В· ${latest.time}` : 'Waiting for signal',
      status: rows.length ? 'Live' : 'Waiting',
      statusTone: rows.length ? lane.tone : 'slate',
    };
  });
});
