function publicDeliveryVerificationEventLabel(count = 0) {
  const copy = publicDeliveryVerificationCopy.value;
  return `${count} ${count === 1 ? copy.eventSingular : copy.eventPlural}`;
}

function deliveryVerificationLedgerLatestLabel(item = null) {
  if (!item) return publicDeliveryVerificationCopy.value.proofPending;
  const project = ledgerProjectFilterLabel(item);
  const when = item.created_at ? formatLedgerDateTime(item.created_at).time : '';
  return [project, when].filter(Boolean).join(' / ') || publicDeliveryVerificationCopy.value.proofPending;
}

const publicDeliveryVerificationGateRows = computed(() => {
  const copy = publicDeliveryVerificationCopy.value;
  return publicDeliveryVerificationGateDefinitions.map((definition, index) => {
    const liveRows = liveFeedAllItemsView.value.filter((item) => liveFeedLaneMatches(item, definition));
    const ledgerRows = ledgerEventItems.value
      .filter((item) => definition.ledgerPredicate?.(item))
      .sort((a, b) => (Date.parse(b.created_at || '') || 0) - (Date.parse(a.created_at || '') || 0));
    const latest = liveRows[0] || null;
    const latestLedger = ledgerRows[0] || null;
    const translated = copy.gates[index] || [];
    const ready = Boolean(liveRows.length || ledgerRows.length);
    return {
      ...definition,
      sequence: String(index + 1).padStart(2, '0'),
      title: translated[0] || definition.key,
      body: translated[1] || '',
      ready,
      liveCount: liveRows.length,
      ledgerCount: ledgerRows.length,
      liveLabel: publicDeliveryVerificationEventLabel(liveRows.length),
      ledgerLabel: publicDeliveryVerificationEventLabel(ledgerRows.length),
      latestLabel: latest ? `${latest.typeLabel} / ${latest.project} / ${latest.time}` : deliveryVerificationLedgerLatestLabel(latestLedger),
      filterLabel: latest?.typeLabel || definition.fallbackFilter,
      actionLabel: liveRows.length ? copy.filterTimeline : copy.waitingAction,
      status: ready ? copy.live : copy.waiting,
      statusTone: ready ? definition.tone : 'slate',
      icon: definition.icon,
      tone: definition.tone,
    };
  });
});

