const liveFeedContributorRows = computed(() => {
  const rows = new Map();
  const upsertContributor = (rawContributor, source = {}) => {
    if (!rawContributor || typeof rawContributor !== 'object') return;
    const workerId = String(rawContributor.worker_id || rawContributor.workerId || source.actor || '').trim();
    const name = String(rawContributor.name || workerId || '').trim();
    if (!workerId && !name) return;
    const key = (workerId || name).toLowerCase();
    const existing = rows.get(key) || {};
    const earnedCents = Number(rawContributor.earned_cents ?? rawContributor.earnedCents) || 0;
    const taskCount = Number(rawContributor.task_count ?? rawContributor.taskCount) || 0;
    const lastActiveAt = rawContributor.last_paid_at || rawContributor.lastPaidAt || source.createdAt || existing.lastActiveAt || '';
    const lastActiveMs = Math.max(
      Date.parse(lastActiveAt) || 0,
      Date.parse(source.createdAt || '') || 0,
      existing.lastActiveMs || 0,
    );
    rows.set(key, {
      key,
      workerId: workerId || existing.workerId || name,
      name: name || existing.name || workerId || 'Contributor',
      kind: rawContributor.kind || existing.kind || 'human contributor',
      agentType: rawContributor.agent_type || rawContributor.agentType || existing.agentType || '',
      taskCount: Math.max(taskCount, existing.taskCount || 0),
      earnedCents: Math.max(earnedCents, existing.earnedCents || 0),
      lastActiveAt: lastActiveAt || existing.lastActiveAt || '',
      lastActiveMs,
      reputationLevel: rawContributor.reputation_level || rawContributor.reputationLevel || existing.reputationLevel || '',
      reputationScore: Number(rawContributor.reputation_score ?? rawContributor.reputationScore ?? existing.reputationScore) || 0,
      riskLevel: rawContributor.risk_level || rawContributor.riskLevel || existing.riskLevel || '',
      activityType: source.activityType || existing.activityType || '',
    });
  };

  for (const item of liveFeedAllItemsView.value) {
    upsertContributor(item.rawContributor, {
      actor: item.actor,
      activityType: item.typeLabel,
      createdAt: item.createdAt,
    });
  }
  for (const contributor of marketplaceData.value.contributors || []) {
    upsertContributor(contributor);
  }

  return Array.from(rows.values())
    .sort((a, b) => (
      (b.lastActiveMs - a.lastActiveMs)
      || (b.taskCount - a.taskCount)
      || (b.earnedCents - a.earnedCents)
      || a.name.localeCompare(b.name)
    ))
    .slice(0, 4)
    .map(mapLiveFeedContributorRow);
});

