    body: empty.bountiesEmpty[1],
  };
});
const marketplaceBountyEmptyActions = computed(() => {
  const actions = publicMarketplaceCopy.value.emptyActions;
  if (marketplaceLoading.value) return [];
  if (marketplaceFiltersActive.value && marketplaceHasBountyRows.value) {
    return [
      { label: actions.clearFilters, icon: X, primary: true, run: () => clearMarketplaceFilters() },
      { label: actions.refreshLiveData, icon: RefreshCw, primary: false, run: () => loadMarketplaceData() },
