const publicBackendControlCopy = computed(() => {
  const copy = publicBackendControlTranslations[activeLocale.value] || publicBackendControlTranslations['en-US'];
  return {
    ...copy,
    surfaces: copy.surfaces?.length ? copy.surfaces : publicBackendControlTranslations['en-US'].surfaces,
    flow: copy.flow?.length ? copy.flow : publicBackendControlTranslations['en-US'].flow,
  };
});

const publicBackendEndpointBaseRows = [
  { id: 'auth_login', method: 'POST', path: '/api/auth/login', category: 'auth', title: 'Auth login', body: 'Create an authenticated customer, contributor, or admin session.' },
  { id: 'auth_me', method: 'GET', path: '/api/auth/me', category: 'auth', title: 'Session identity', body: 'Resolve the current actor, role, wallet, OAuth, and dashboard access.' },
  { id: 'repo_issues', method: 'POST', path: '/api/public/repo/issues', category: 'repository', title: 'Repository issue import', body: 'Import GitHub issues and score them into task-ready repository signals.' },
  { id: 'project_create', method: 'POST', path: '/api/projects', category: 'projects', title: 'Project create', body: 'Create funded project records with scope, files, budget, and payment context.' },
  { id: 'task_graph', method: 'GET', path: '/api/projects/{project_id}/task-graph', category: 'tasks', title: 'Task graph', body: 'Read AI-generated task packets, dependency order, rewards, and lane routing.' },
  { id: 'ai_workflow', method: 'GET', path: '/api/projects/{project_id}/ai-workflow', category: 'ai', title: 'AI workflow', body: 'Inspect repository scan, issue analysis, routing, review, and deployment signals.' },
  { id: 'escrow', method: 'GET', path: '/api/projects/{project_id}/escrow', category: 'payments', title: 'Escrow status', body: 'Read project reserve, task reserve, release readiness, payouts, and remaining balance.' },
  { id: 'submit_evidence', method: 'POST', path: '/api/tasks/{task_id}/submit', category: 'evidence', title: 'Submit evidence', body: 'Attach PR links, tests, screenshots, deployment references, and review notes.' },
  { id: 'ledger_events', method: 'GET', path: '/api/public/ledger/events?limit=100', category: 'ledger', title: 'Ledger events', body: 'Fetch sanitized escrow, payout, token, PR, deployment, and release proof rows.' },
  { id: 'websocket', method: 'WS', path: '/api/ws', category: 'realtime', title: 'WebSocket gateway', body: 'Stream marketplace, project, PR, deployment, AI, payout, and admin events.' },
];

const publicBackendEndpointRows = computed(() => {
  const manifestRows = protocolEndpointRows.value.map((endpoint) => ({
    id: endpoint.id,
    method: endpoint.method,
    path: endpoint.path,
    category: endpoint.category,
    title: endpoint.id ? toTitleLabel(endpoint.id) : endpoint.category,
    body: endpoint.body,
  }));
  const rows = manifestRows.length ? manifestRows : publicBackendEndpointBaseRows;
  const seen = new Set();
  return rows.concat(publicBackendEndpointBaseRows)
    .filter((endpoint) => {
      const key = `${endpoint.method}:${endpoint.path}`;
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    })
    .slice(0, 10);
});

const publicBackendEndpointSourceLabel = computed(() =>
  protocolEndpointRowsRaw.value.length ? publicBackendControlCopy.value.manifestSource : publicBackendControlCopy.value.routeMapSource,
);

const publicBackendAuthReadyCount = computed(() => [
  githubOAuthReady.value,
  googleOAuthReady.value,
  Boolean(runtimeConfig.value?.paypal_ready || runtimeConfig.value?.crypto_ready || runtimeConfig.value?.dev_payment_enabled),
].filter(Boolean).length);

const publicBackendControlStats = computed(() => {
  const copy = publicBackendControlCopy.value.stats;
  const endpointCount = protocolStatsView.value.endpoints || publicBackendEndpointRows.value.length;
  const realtimeCount = liveFeedAllItemsView.value.length;
  const escrowCents = Number(marketplaceStats.value.total_budget_cents) || publicVerifiedFundingCents.value;
  return [
    { label: copy.endpoints, value: String(endpointCount), caption: copy.endpointsCaption, icon: Code2, tone: 'blue' },
    { label: copy.realtime, value: String(realtimeCount), caption: copy.realtimeCaption, icon: Zap, tone: 'purple' },
    { label: copy.escrow, value: formatPublicMRGFromCents(escrowCents), caption: copy.escrowCaption, icon: CircleDollarSign, tone: 'green' },
    { label: copy.auth, value: `${publicBackendAuthReadyCount.value} / 3`, caption: copy.authCaption, icon: LockKeyhole, tone: 'amber' },
  ];
});

const publicBackendRuntimeStackRows = computed(() => [
  { label: 'Go / Rust', value: 'API control plane', icon: Box, tone: 'blue' },
  { label: 'PostgreSQL', value: 'Workflow state', icon: ShieldCheck, tone: 'green' },
  { label: 'Redis', value: 'Realtime cache', icon: Zap, tone: 'amber' },
  { label: 'GitHub API', value: 'Repo and PR sync', icon: GitBranch, tone: 'purple' },
  { label: 'OpenAI API', value: 'AI orchestration', icon: Bot, tone: 'green' },
  { label: 'WebSocket gateway', value: '/api/ws events', icon: Code2, tone: 'blue' },
]);

function publicBackendEndpointCount(pattern) {
  const matcher = pattern instanceof RegExp ? pattern : new RegExp(String(pattern || ''), 'i');
  return publicBackendEndpointRows.value.filter((endpoint) =>
    matcher.test([endpoint.id, endpoint.path, endpoint.category, endpoint.title, endpoint.body].filter(Boolean).join(' ')),
  ).length;
}

const publicBackendSurfaceRows = computed(() => {
  const copy = publicBackendControlCopy.value;
  const liveCount = liveFeedAllItemsView.value.length;
  const ledgerCount = ledgerEventItems.value.length;
  const agentTasks = Number(agentQueueData.value.stats?.total_count) || (agentQueueData.value.tasks || []).length;
  const openTasks = Number(marketplaceStats.value.open_task_count) || (marketplaceData.value.bounties || []).length;
  const escrow = formatPublicMRGFromCents(Number(marketplaceStats.value.total_budget_cents) || publicVerifiedFundingCents.value);
  const definitions = [
    { key: 'auth', icon: LockKeyhole, tone: 'green', signal: `${publicBackendAuthReadyCount.value} / 3 ${copy.stats.auth}`, ready: publicBackendAuthReadyCount.value > 0 },
    { key: 'repo', icon: GitBranch, tone: 'blue', signal: `${publicBackendEndpointCount(/repo|issue|github/i)} routes`, ready: true },
    { key: 'ai', icon: Bot, tone: 'purple', signal: `${agentTasks} agent tasks`, ready: agentTasks > 0 },
    { key: 'tasks', icon: ListTodo, tone: 'amber', signal: `${openTasks} open tasks`, ready: openTasks > 0 },
    { key: 'payments', icon: CreditCard, tone: 'green', signal: `${escrow} escrow`, ready: Number(marketplaceStats.value.total_budget_cents) > 0 },
    { key: 'realtime', icon: Zap, tone: 'purple', signal: `${liveCount} events`, ready: liveCount > 0 },
    { key: 'ledger', icon: ShieldCheck, tone: 'blue', signal: `${ledgerCount} proof rows`, ready: ledgerCount > 0 },
    { key: 'protocol', icon: Code2, tone: 'amber', signal: `${protocolStatsView.value.endpoints || publicBackendEndpointRows.value.length} endpoints`, ready: true },
  ];
  return definitions.map((definition, index) => {
    const row = copy.surfaces[index] || [];
    return {
      ...definition,
      title: row[0] || definition.key,
      body: row[1] || '',
      status: definition.ready ? copy.ready : copy.syncing,
      statusTone: definition.ready ? 'green' : 'slate',
    };
  });
});

const publicBackendFlowRows = computed(() => {
  const copy = publicBackendControlCopy.value;
  const signals = [
    `${publicBackendAuthReadyCount.value} auth rails`,
    `${publicBackendEndpointCount(/repo|issue|github/i)} repo routes`,
    `${Number(agentQueueData.value.stats?.total_count) || (agentQueueData.value.tasks || []).length} agent tasks`,
    `${Number(marketplaceStats.value.open_task_count) || (marketplaceData.value.bounties || []).length} open tasks`,
    formatPublicMRGFromCents(Number(marketplaceStats.value.total_budget_cents) || publicVerifiedFundingCents.value),
    `${liveFeedAllItemsView.value.length} realtime events`,
    `${publicBackendEndpointCount(/submit|review|release|deployment|pull|evidence/i)} evidence routes`,
    `${ledgerEventItems.value.length} proof rows`,
  ];
  return copy.flow.map((row, index) => ({
    key: `backend-flow-${index}`,
    title: row[0],
    body: row[1],
    signal: signals[index] || publicBackendEndpointSourceLabel.value,
  }));
});

