      tone: row.tone || 'purple',
      icon: row.icon || Bot,
      meta: row.meta || '',
      reference: row.reference || '',
      url: row.url || '',
      createdAt: row.createdAt || '',
      order: Number(row.order) || 0,
    });
  };

  dashboardAIWorkflowStages.value.slice(0, 5).forEach((stage, index) => {
    pushRow({
      key: `ai-workflow-${stage.id || index}`,
      title: stage.title,
      body: stage.body,
      source: 'AI workflow',
      status: stage.status,
      tone: stage.tone || 'purple',
      icon: Bot,
      meta: dashboardAIWorkflowView.value.status,
      order: 10 + index,
    });
  });

  (dashboardAIWorkflow.value?.signals || []).slice(0, 4).forEach((signal, index) => {
    const delegation = liveFeedDelegationSummary(signal);
    pushRow({
      key: `ai-workflow-signal-${signal.id || index}`,
      title: signal.title || toTitleLabel(signal.type || 'Agent signal'),
      body: signal.body,
      source: 'Agent signal',
      status: toTitleLabel(signal.status || 'live'),
      tone: signal.type === 'deployment_validation' ? 'blue' : 'purple',
      icon: signal.type === 'deployment_validation' ? Rocket : Bot,
      meta: delegation || dashboardAIWorkflowView.value.status,
      reference: shortLedgerReference(signal.reference || ''),
      url: signal.url || '',
      createdAt: signal.created_at,
      order: 20 + index,
    });
  });

  dashboardWorkflowPulseStages.value
    .filter((stage) => /ai|agent|scan|routing|review|deploy|validation|task/i.test(`${stage.title} ${stage.body}`))
    .slice(0, 4)
    .forEach((stage, index) => {
      pushRow({
        key: `workflow-pulse-${stage.id || index}`,
        title: stage.title,
        body: stage.body,
        source: 'Workflow pulse',
        status: `${stage.progress}%`,
        tone: stage.tone || 'blue',
        icon: Zap,
        meta: dashboardWorkflowPulseView.value.status,
        order: 30 + index,
      });
    });

  dashboardRepositoryFindingRows.value.slice(0, 3).forEach((finding, index) => {
    pushRow({
      key: `repo-finding-${finding.id}`,
      title: `Scan: ${finding.title}`,
      body: `${finding.category} at ${finding.location}. ${finding.body}`,
      source: 'Repository scan',
      status: finding.severity,
      tone: finding.tone,
      icon: Search,
      meta: dashboardRepositoryScanTargetLabel.value,
      order: 50 + index,
    });
  });

  dashboardRoutingRouteRows.value.slice(0, 3).forEach((route, index) => {
    pushRow({
      key: `routing-${route.id}`,
      title: `Route #${route.issueNumber} to ${route.lane}`,
      body: `${route.candidate} matched as ${route.workerKind}. ${route.reason}`,
      source: 'Contributor routing',
      status: `${route.score}% match`,
      tone: route.score >= 80 ? 'green' : route.score >= 60 ? 'blue' : 'amber',
      icon: GitBranch,
      meta: route.action,
      order: 70 + index,
    });
  });

  dashboardDeploymentStages.value.slice(0, 3).forEach((stage, index) => {
    pushRow({
      key: `deployment-${stage.id}`,
      title: `Deploy: ${stage.title}`,
      body: stage.body,
      source: 'Deployment agent',
      status: stage.status,
      tone: stage.tone || 'green',
      icon: Rocket,
      meta: dashboardDeploymentView.value.status,
      reference: stage.reference,
      order: 90 + index,
    });
  });

  dashboardProjectLedger.value
    .filter((entry) => entry.type === 'ai_review' || entry.type === 'agent_action')
    .slice()
    .reverse()
    .slice(0, 4)
    .forEach((entry, index) => {
      const meta = liveFeedMetaFor(entry.type);
      const when = formatLedgerDateTime(entry.created_at);
      const reference = entry.reference || entry.entry_hash || `#${entry.sequence}`;
      pushRow({
        key: `ledger-ai-${entry.sequence || index}-${reference}`,
        title: meta.type,
        body: ledgerTransparencySecondary(entry.type) || 'Agent proof attached to this project.',
        source: 'Ledger proof',
        status: toTitleLabel(entry.status || 'verified'),
        tone: meta.tone || 'purple',
        icon: meta.icon || Bot,
        meta: when.full,
        reference: shortLedgerReference(reference),
        createdAt: entry.created_at,
        order: 110 + index,
      });
    });

  return rows
    .sort((a, b) => {
      const bTime = Date.parse(b.createdAt || '') || 0;
      const aTime = Date.parse(a.createdAt || '') || 0;
      if (bTime || aTime) return bTime - aTime;
      return a.order - b.order;
    })
    .slice(0, 10);
});
