const dashboardDeploymentPacket = computed(() => {
  const deployment = dashboardDeployment.value;
  const packet = deployment?.validation_packet || {};
  const projectID = deployment?.project_id || selectedDashboardProjectID.value || '';
  const actionID = deploymentValidationActionID(projectID);
  const blockers = Array.isArray(packet.blockers) ? packet.blockers : [];
  const warnings = Array.isArray(packet.warnings) ? packet.warnings : [];
  const nextAction = packet.next_action || blockers[0] || warnings[0] || '';
  const canRecord = packet.can_record === true && Boolean(packet.action_endpoint);
  return {
    visible: Boolean(deployment && (canRecord || packet.status || nextAction)),
    status: toTitleLabel(packet.status || (canRecord ? 'ready' : 'waiting')),
    body: nextAction || (canRecord ? 'Deployment agent can record validation evidence.' : 'Deployment validation packet is waiting for more evidence.'),
    canRecord,
    busy: releasingTaskID.value === actionID,
    actionID,
    packet,
  };
});
