  }
  if (dashboardSection.value === 'estimate') {
    return {
      icon: Calculator,
      label: priceEvaluationBusy.value ? 'Estimating' : (priceEvaluation.value ? 'Re-estimate' : 'Estimate'),
      disabled: priceEvaluationBusy.value,
      run: () => runProjectPriceEvaluation(),
    };
  }
  return {
    icon: view.primaryIcon,
    label: view.primaryLabel,
    disabled: false,
    run: view.primaryAction,
  };
});
