  return {
    score,
    worker: audit.worker_id ? formatClaimWorkerID(audit.worker_id) : (workerDashboardView.value.title || 'Worker'),
    level: toTitleLabel(audit.level || 'new'),
    riskLabel: `${toTitleLabel(risk || 'low')} risk`,
    riskTone: workerAuditRiskTone(risk),
    summary: `${completed} completed task${completed === 1 ? '' : 's'}, ${rewardRows} payout row${rewardRows === 1 ? '' : 's'}, and ${formatMRGFromCents(audit.reward_cents || workerDashboardStats.value.reward_cents)} recorded from accepted work.`,
