    .map((label) => items.find((item) => item.label === label))
    .filter(Boolean);
  const active = items.find((item) => isDashboardNavActive(item));
  if (active && !rows.some((item) => item.mobileKey === active.mobileKey)) {
    rows.splice(Math.max(0, rows.length - 1), 1, active);
  }
  return rows.slice(0, 4).map((item) => ({
    ...item,
    mobileLabel: item.label === 'Worker Dashboard' ? 'Worker' : item.label === 'My Projects' ? 'Projects' : item.label,
  }));
});

const dashboardMobileMoreNav = computed(() => {
  const primaryKeys = new Set(dashboardMobilePrimaryNav.value.map((item) => item.mobileKey));
  return dashboardMobileNavItems.value.filter((item) => !primaryKeys.has(item.mobileKey));
});

const dashboardTabs = ['Overview', 'Tasks', 'AI Logs', 'Activity', 'Ledger', 'Files', 'Settings'];

function initialsFor(value = '') {
  const parts = value
    .replace(/@.*/, '')
    .split(/[\s._-]+/)
    .filter(Boolean);
  const letters = parts.length > 1
    ? `${parts[0][0]}${parts[1][0]}`
    : (parts[0] || 'MR').slice(0, 2);
  return letters.toUpperCase();
}

function shortWallet(value = '') {
  const address = String(value || '').trim();
  if (address.length <= 14) return address || 'Solana MRG wallet';
  return `${address.slice(0, 6)}...${address.slice(-6)}`;
}

function normalizeFrontendWalletAddress(value = '') {
  return String(value || '')
    .trim()
    .replace(/^wallet:/i, '')
    .replace(/^solana:/i, '')
    .replace(/^sol:/i, '');
}

function normalizeFrontendGitHubUsername(value = '') {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/^github:/i, '')
    .replace(/^@/, '')
    .replace(/^\/+|\/+$/g, '');
}

function claimWorkerIDForProfile(profile = user.value) {
  const source = profile || {};
  const github = normalizeFrontendGitHubUsername(source.github_username || source.githubUsername);
  if (github) return `github:${github}`;
  const wallet = normalizeFrontendWalletAddress(source.wallet_address || source.walletAddress);
  if (wallet) return wallet;
  return String(source.id || source.user_id || source.userID || '').trim();
}

function formatClaimWorkerID(value = '') {
  const workerID = String(value || '').trim();
  if (!workerID || workerID === 'current-user') {
    return user.value ? 'Current session' : 'Sign in to attach identity';
  }
  if (workerID.toLowerCase().startsWith('github:')) return workerID;
  if (/^[1-9A-HJ-NP-Za-km-z]{32,44}$/.test(workerID)) return shortWallet(workerID);
  return shortLedgerReference(workerID);
}

function workerAuditRiskTone(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (['critical', 'high', 'blocked'].includes(normalized)) return 'red';
  if (['medium', 'elevated', 'review'].includes(normalized)) return 'amber';
  if (['low', 'clear', 'trusted', 'none'].includes(normalized)) return 'green';
  return 'slate';
}

function randomOAuthState() {
  if (hasWindow && window.crypto?.getRandomValues) {
    const bytes = new Uint8Array(16);
    window.crypto.getRandomValues(bytes);
    return Array.from(bytes, (byte) => byte.toString(16).padStart(2, '0')).join('');
  }
  return `${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

function openWalletOnScan(address = '') {
