async function executeAdminOpsAction(item = {}) {
  if (!item?.id || releasingTaskID.value) return;
  const packet = item.actionPacket || {};
  if (!packet.can_execute || !packet.action_endpoint) {
    showToast(packet.next_action || 'This admin item requires manual review.');
    return;
  }
  releasingTaskID.value = item.id;
  try {
    const actionPayload = packet.payload || packet.resolution_payload || packet.resolutionPayload || {};
    const response = await api(packet.action_endpoint, {
      method: packet.method || 'POST',
      body: JSON.stringify(actionPayload),
    });
    await Promise.all([
      loadAdminConsoleData({ silent: true }),
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
      loadDashboardData({ silent: true }),
    ]);
    if (response?.ok && (packet.resolution_payload || packet.resolutionPayload)) {
      showToast(`${item.actionLabel} recorded for admin ops item.`);
    } else {
      showToast(`Released payout for task #${response?.issue_number || item.task || ''}.`);
    }
  } catch (error) {
    showToast(error.message || 'Could not execute admin action.');
  } finally {
    releasingTaskID.value = '';
  }
}

function adminOpsQueueActionBusyID(item = {}, action = {}) {
  return `admin-ops-action:${item.id || 'ops'}:${action.id || action.type || 'action'}`;
}

function adminOpsQueueActionBusy(item = {}, action = {}) {
  return Boolean(releasingTaskID.value);
}

function adminOpsQueueActionRunning(item = {}, action = {}) {
  return releasingTaskID.value === adminOpsQueueActionBusyID(item, action);
}

function adminOpsQueueActionIcon(action = {}) {
  switch (action.type) {
  case 'review_task_pulls':
    return GitPullRequest;
  case 'run_ssl_review':
    return ShieldCheck;
  case 'refresh_admin_ops':
    return RefreshCw;
  case 'open_url':
    return ExternalLink;
  default:
    return Link2;
  }
}

async function handleAdminOpsQueueAction(item = {}, action = {}) {
  if (!item?.id || !action?.type || releasingTaskID.value) return;
  const busyID = adminOpsQueueActionBusyID(item, action);
  releasingTaskID.value = busyID;
  try {
    switch (action.type) {
    case 'open_url': {
      const target = action.url || item.url || item.rawReference;
      if (!target) {
        showToast('No public admin ops URL is attached.');
        break;
      }
      openExternalURL(target);
      showToast(`Opened ${action.label || 'admin ops reference'}.`);
      break;
    }
    case 'refresh_admin_ops':
      await loadAdminConsoleData({ silent: true });
      showToast('Admin ops queue refreshed.');
      break;
    case 'review_task_pulls': {
      dashboardSection.value = 'admin';
      dashboardSearch.value = item.issueNumber ? String(item.issueNumber) : (item.taskID || item.reference || item.project || '');
      showToast(`Filtered admin ops for ${item.task || item.reference || 'PR review'}.`);
      break;
    }
    case 'run_ssl_review': {
      const options = { method: action.method || 'POST' };
      if (action.payload && Object.keys(action.payload).length) {
        options.body = JSON.stringify(action.payload);
      }
      const rows = await api(action.endpoint || '/api/admin/ssl/review', options);
      await loadAdminConsoleData({ silent: true });
      showToast(`Reviewed ${Array.isArray(rows) ? rows.length : 0} SSL domain${Array.isArray(rows) && rows.length === 1 ? '' : 's'}.`);
      break;
    }
    default:
      if (action.url || item.url) {
        openExternalURL(action.url || item.url);
        showToast(`Opened ${action.label || 'admin ops reference'}.`);
      } else {
        showToast(`${action.label || 'Admin ops action'} requires manual review.`);
      }
    }
  } catch (error) {
    showToast(error.message || 'Could not run admin ops action.');
  } finally {
    releasingTaskID.value = '';
  }
}

async function decideAdminOpsProposal(item = {}, decision = '') {
  const proposalID = String(item.proposalID || '').trim();
  const normalizedDecision = String(decision || '').trim().toLowerCase();
  if (!proposalID || adminProposalDecisionID.value || !['accepted', 'declined'].includes(normalizedDecision)) return;

  adminProposalDecisionID.value = proposalID;
  try {
    const response = await api(`/api/proposals/${encodeURIComponent(proposalID)}/decision`, {
      method: 'POST',
      body: JSON.stringify({ decision: normalizedDecision }),
    });
    await Promise.allSettled([
      loadAdminConsoleData({ silent: true }),
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
      loadDashboardData({ silent: true }),
      loadWorkerDashboardData({ silent: true }),
    ]);
    const status = response?.proposal?.status || normalizedDecision;
    showToast(status === 'accepted' ? `Accepted proposal for ${item.task || 'task'}.` : `Declined proposal for ${item.task || 'task'}.`);
  } catch (error) {
    showToast(error.message || 'Could not update proposal.');
  } finally {
    adminProposalDecisionID.value = '';
  }
}

