    protocol_version: payload.protocol_version || 'mergeos.delivery.snapshot.v1',
    kind: payload.kind || 'project_delivery_snapshot',
    scope: payload.scope || 'authenticated',
    project_id: payload.project_id || fallbackProjectID,
    generated_at: payload.generated_at,
    errors: payload.errors && typeof payload.errors === 'object' ? payload.errors : {},
  };
}

function applyDashboardDeliverySnapshotPayload(payload = {}, fallbackProjectID = '') {
  const projectID = payload.project_id || payload.project?.project_id || fallbackProjectID;
  dashboardDeliverySnapshot.value = normalizeDashboardDeliverySnapshotPayload(payload, projectID);
  if (payload.workflow_pulse || payload.ai_workflow || payload.task_graph) {
    dashboardWorkflowPulse.value = normalizeDashboardWorkflowPulsePayload(
      payload.workflow_pulse || dashboardWorkflowPulseFromProjectDashboard(payload, projectID),
      projectID,
    );
    dashboardWorkflowPulseError.value = '';
  }
  if (payload.ai_workflow) {
    dashboardAIWorkflow.value = normalizeDashboardAIWorkflowPayload(payload.ai_workflow, projectID);
    dashboardAIWorkflowError.value = '';
  }
  if (payload.repository_scan) {
    dashboardRepositoryScan.value = normalizeDashboardRepositoryScanPayload(payload.repository_scan, projectID);
    dashboardRepositoryScanError.value = '';
  }
  if (payload.task_graph) {
    dashboardTaskGraph.value = normalizeDashboardTaskGraphPayload(payload.task_graph, projectID);
    dashboardTaskGraphError.value = '';
  }
  if (payload.routing) {
    dashboardRouting.value = normalizeDashboardRoutingPayload(payload.routing, projectID);
    dashboardRoutingError.value = '';
  }
  if (payload.pr_monitor || payload.pull_requests) {
    dashboardPullRequests.value = normalizeDashboardPullRequestsPayload(payload.pr_monitor || payload.pull_requests, projectID);
    dashboardPullRequestsError.value = '';
  }
  if (payload.deployment) {
    dashboardDeployment.value = normalizeDashboardDeploymentPayload(payload.deployment, projectID);
    dashboardDeploymentError.value = '';
  }
  if (payload.escrow) {
    dashboardEscrow.value = normalizeDashboardEscrowPayload(payload.escrow, projectID);
    dashboardEscrowError.value = '';
  }
}

