async function loadDashboardProjectDashboardData(projectID, options = {}) {
  const targetProjectID = String(projectID || '').trim();
  if (!token.value || !targetProjectID) {
    dashboardProjectDashboard.value = null;
    dashboardProjectDashboardLoading.value = false;
    dashboardProjectDashboardError.value = '';
    return;
  }

  const silent = Boolean(options.silent);
  if (!silent) dashboardProjectDashboardLoading.value = true;
  dashboardProjectDashboardError.value = '';
  try {
    const payload = await api(`/api/projects/${encodeURIComponent(targetProjectID)}/dashboard`);
    if (targetProjectID !== selectedDashboardProjectID.value) return;
    dashboardProjectDashboard.value = normalizeDashboardProjectDashboardPayload(payload, targetProjectID);
  } catch (error) {
    if (targetProjectID === selectedDashboardProjectID.value) {
      dashboardProjectDashboard.value = null;
      dashboardProjectDashboardError.value = error.message || 'Could not load project proposals';
    }
  } finally {
    dashboardProjectDashboardLoading.value = false;
  }
}

function normalizeDashboardProjectDashboardPayload(payload = {}, fallbackProjectID = '') {
  return {
    protocol_version: payload.protocol_version || 'mergeos.customer-dashboard.v1',
    kind: payload.kind || 'customer_dashboard',
    project: payload.project || { project_id: fallbackProjectID },
    escrow: payload.escrow || null,
    payouts: payload.payouts || null,
    deployment: payload.deployment || null,
    ai_workflow: payload.ai_workflow || null,
    task_graph: payload.task_graph || null,
    repository_scan: payload.repository_scan || null,
    pull_requests: payload.pull_requests || null,
    proposals: Array.isArray(payload.proposals) ? payload.proposals : [],
    updated_at: payload.updated_at || '',
  };
}

async function loadDashboardDeliverySnapshotData(projectID, options = {}) {
  const targetProjectID = String(projectID || '').trim();
  if (!token.value || !targetProjectID) {
    resetDashboardProjectProtocolState();
    return;
  }

  const silent = Boolean(options.silent);
  if (!silent) {
    dashboardDeliverySnapshotLoading.value = true;
    dashboardDeploymentLoading.value = true;
    dashboardEscrowLoading.value = true;
    dashboardAIWorkflowLoading.value = true;
    dashboardWorkflowPulseLoading.value = true;
    dashboardPullRequestsLoading.value = true;
    dashboardRoutingLoading.value = true;
    dashboardRepositoryScanLoading.value = true;
    dashboardTaskGraphLoading.value = true;
  }
  dashboardDeliverySnapshotError.value = '';
  try {
    const payload = await api(`/api/projects/${encodeURIComponent(targetProjectID)}/dashboard`);
    if (targetProjectID !== selectedDashboardProjectID.value) return;
    applyDashboardDeliverySnapshotPayload(payload, targetProjectID);
  } catch (error) {
    if (targetProjectID === selectedDashboardProjectID.value) {
      dashboardDeliverySnapshot.value = null;
      dashboardDeliverySnapshotError.value = error.message || 'Could not load delivery snapshot';
    }
  } finally {
    dashboardDeliverySnapshotLoading.value = false;
    dashboardDeploymentLoading.value = false;
    dashboardEscrowLoading.value = false;
    dashboardAIWorkflowLoading.value = false;
    dashboardWorkflowPulseLoading.value = false;
    dashboardPullRequestsLoading.value = false;
    dashboardRoutingLoading.value = false;
    dashboardRepositoryScanLoading.value = false;
    dashboardTaskGraphLoading.value = false;
  }
}

async function loadDashboardRepositoryIntelligenceData(projectID, options = {}) {
  const targetProjectID = String(projectID || '').trim();
  if (!token.value || !targetProjectID) {
    resetDashboardRepositoryIntelligenceState();
    return;
  }

  const silent = Boolean(options.silent);
  if (!silent) {
    dashboardRepositoryScanLoading.value = true;
    dashboardTaskGraphLoading.value = true;
  }
  dashboardRepositoryScanError.value = '';
  dashboardTaskGraphError.value = '';

  try {
    const [scanResult, graphResult] = await Promise.allSettled([
      api(`/api/projects/${encodeURIComponent(targetProjectID)}/repo-scan`),
      api(`/api/projects/${encodeURIComponent(targetProjectID)}/task-graph`),
    ]);
    if (targetProjectID !== selectedDashboardProjectID.value) return;

    if (scanResult.status === 'fulfilled') {
      dashboardRepositoryScan.value = normalizeDashboardRepositoryScanPayload(scanResult.value, targetProjectID);
    } else {
      dashboardRepositoryScan.value = null;
      dashboardRepositoryScanError.value = scanResult.reason?.message || 'Could not load repository scan.';
    }

    if (graphResult.status === 'fulfilled') {
      dashboardTaskGraph.value = normalizeDashboardTaskGraphPayload(graphResult.value, targetProjectID);
    } else {
      dashboardTaskGraph.value = null;
      dashboardTaskGraphError.value = graphResult.reason?.message || 'Could not load task graph.';
    }
  } finally {
    dashboardRepositoryScanLoading.value = false;
    dashboardTaskGraphLoading.value = false;
  }
}

